720	    func startTimerMacAddress(currentVin: String) {
721	        let timer = Timer(timeInterval: 5, repeats: true) { [weak self] _ in
722	            if let digitalKey: DigitalKey = self?.validBlePrivateKey() {
723	                if digitalKey.bleInfo?.macAddress != nil {
724	                    self?.fetchMacTimer?.invalidate()
725	                    self?.fetchMacTimer = nil
726	                    self?.bleInfo = digitalKey.bleInfo
727	                    return
728	                }
729	            }
730	            self?.requestMacAddressOnce(currentVin: currentVin, callBack: nil)
731	        }
732	        RunLoop.current.add(timer, forMode: .common)
733	        self.fetchMacTimer = timer
734	    }
