803	    public func removeKey(digitalKey: DigitalKey, success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>) {
804	        var keyCardType = digitalKey.keyCardType
805	        let plugin = self.createPlugin(keyCardType: keyCardType)
806	        if (plugin == nil) {
807	            let resp = VehicleError(code: .NotSupported, desc:"尚未支持，操作失败")
808	            failed(resp)
809	            return
810	        }
811	        self.removeKeyPlugin = plugin
812	        self.delegate?.willRemoveKey?(vin: self.vehicle.vin, keyCardType: keyCardType)
813	        plugin!.removeKey(digitalKey: digitalKey) { data in
814	            self.removeKeyPlugin = nil
815	            var keyReturned = false
816	            if let reponse: RemoveDigitalKeySuccessResponse = data {
817	                if let digitalKeyList = data?.digitalKeyList {
818	                    if (digitalKeyList.count ?? 0) > 0 {
819	                        keyReturned = true
820	                        for item in digitalKeyList {
821	                            self.removeSuccess(digitalKey: item)
822	                        }
823	                    }
824	                }
825	            }
826	            if keyReturned == false {
827	                self.removeSuccess(digitalKey: digitalKey)
828	            }
829	            self.repareBleInfo()
830	            self.delegate?.didRemoveKey?(vin: self.vehicle.vin, keyCardType: digitalKey.keyCardType, success: true)
831	            success()
832	        } failed: { error in
833	            self.removeKeyPlugin = nil
834	            self.delegate?.didRemoveKey?(vin: self.vehicle.vin, keyCardType: digitalKey.keyCardType, success: false)
835	            failed(error)
836	        }
837	    }
