953	        let digitalKeyList = DigitalKey.queryDigitalKeyList(vin: vehicle.vin ?? "")
954	        if digitalKeyList.count > 0 {
955	            for digitalKey in digitalKeyList {
956	                downloadKeyMessagesCheck(digitalKey: digitalKey, vehicle: vehicle)
