//
//  DigitalKeyManager.swift
//  XPVehicleSDK
//
//  Created by Xpeng on 2023/12/5.
//

import Foundation
import Combine

@objc(XPDigitalKeyManagerDelegate)
protocol DigitalKeyManagerDelegate : NSObjectProtocol {
    @objc optional func willCreateKey(vin: String!, keyCardType: KeyCardType)
    @objc optional func didCreateKey(vin: String!, keyCardType: KeyCardType, success: Bool)
    @objc optional func willRemoveKey(vin: String!, keyCardType: KeyCardType)
    @objc optional func didRemoveKey(vin: String!, keyCardType: KeyCardType, success: Bool)

    @objc optional func didLoadKeys(vin: String!)
}

//@objc(XPDigitalKeyManager)
class DigitalKeyManager: NSObject, DigitalKeyManagerProtocol, ObservableObject, MonaKeyStatusDelegate {

    var uid: UInt64                             // 用户UID
    @Published public var bleInfo: BLEInfo?     // BLE 信息

    @objc @Published public var digitalKeyList: [DigitalKey] = []

    var isTboxBad: Bool = false          // TBOX 是否在线

    private var _selfCalibration: PollingSelfCalibrationProtocol?
    var selfCalibration: PollingSelfCalibrationProtocol? {
        return _selfCalibration
    }

    var cancellables = Set<AnyCancellable>()
    let keyTypeList: [Int] // KeyCardType 支持的钥匙类型
    let vehicle: VehicleInfo.Vehicle
    weak var delegate: DigitalKeyManagerDelegate?
    var createKeyPlugin: DigitalKeyManagerPluginProtocol?
    var removeKeyPlugin: DigitalKeyManagerPluginProtocol?
    let vehiclePreference: VehiclePreference
    weak var communication: VehicleCommunication?
    var fetchMacTimer: Timer?
    static var staticPlugin: [String:DigitalKeyManagerPluginProtocol?] = [:]
    static let serialPluginQueue = DispatchQueue(label: "com.xpvehicle.sdk.digitalkey.serialQueue")
    static var keyManagerMap: [KeyCardType: AnyObject] = [
        KeyCardType.SAFE:IFAAKeyManager.self,
        KeyCardType.CERT:IFAAKeyManager.self,
        KeyCardType.SELF:SelfKeyManager.self,
        KeyCardType.MONA_BLE:MonaKeyManager.self,
        KeyCardType.NFC_WATCH:NFCKeyManager.self,
        KeyCardType.SELF_V3:SelfKeyV3Manager.self,
        KeyCardType.CCC:SelfKeyV3Manager.self
    ]

    private var _carKeyPlugin: CarKeyPassAccessProtocol?
    private var currentCCCVid: String?

    var carKeyPlugin: CarKeyPassAccessProtocol? {
        guard let cccVid = vehiclePreference.extInfo?.cccVid else { return nil }
        if !vehiclePreference.function.CCC_DK_THIRD {
            return nil;
        }
        if _carKeyPlugin == nil || currentCCCVid != cccVid {
            guard CarKeyConditionCheck.isSupportCarKeySoftware(cccVid: vehiclePreference.extInfo?.cccVid, bleKeyVersion: Int(vehiclePreference.abilityConfig.bleKeyVersion.rawValue), isSupportCCC: vehiclePreference.function.CCC_DK_THIRD) else { return nil }
            let plugin = CarKeyPassAccesser(cccVid: cccVid, delegate: self)
            _carKeyPlugin = plugin
            currentCCCVid = cccVid
            plugin.initConfigure()
        }
        return _carKeyPlugin
    }

    public init(uid: UInt64, vehicle: VehicleInfo.Vehicle!, keyTypeList: [Int], vehiclePreference: VehiclePreference, communication: VehicleCommunication? = nil) {
        Log.i("DigitalKeyManager init vin:\(vehicle.vin ?? "")")
        self.uid = uid
        self.vehicle = vehicle
        self.keyTypeList = keyTypeList
        self.vehiclePreference = vehiclePreference
        self.communication = communication
        super.init()

        loadAllDigitalKey(uid: uid, isFromInit: true)

        NotificationCenter.default.addObserver(self, selector: #selector(refreshDigitalKeyFromNotification), name: VehicleNotification.CallBackConnectAuthError, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(connectStateChanged), name: VehicleNotification.BLEConnectStateChanged, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(networkResumeAction), name: VehicleNotification.NetworkResume, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(tboxRunStateNotification), name: VehicleNotification.tboxRunStateNotification, object: nil)

        // 自标定协议实现
        var calibrationVer = BleSelfCalibrationVersion.v1
        if vehiclePreference.abilityConfig.isSupportPollingV1 == true {
            calibrationVer = .v1
        } else if vehiclePreference.abilityConfig.isSupportPollingV2 == true {
            calibrationVer = .v2
        } else {
            calibrationVer = .v3
        }

        if let communication = communication {
            _selfCalibration = SelfCalibrationManger(communication: communication, version: calibrationVer)
        }

        CarService.registerMonaKeyListener(listener: self)
        //        mockDigitalKey("00:60:37:6b:4b:5d")  // BLE_MOCK 本地调试蓝牙件时打开，但不要提交
        Log.i("DigitalKeyManager init end vin:\(vehicle.vin ?? "")")
    }

    deinit {
        Log.i(tag:"DigitalKeyManager", "DigitalKeyManager deinit")
        NotificationCenter.default.removeObserver(self)
        CarService.unregisterMonaKeyListener(listener: self)
        self.stopTimerMacAddress()
    }

    func mockDigitalKey(_ address: String) {
        let digitalKey = DigitalKey(uid: uid, vin: vehicle.vin ?? "", keyCardType: KeyCardType.SELF, cardNo: "1000")
        setDigitalKeyList(digitalKeyList: [digitalKey])
        let bleInfo = BLEInfo()
        bleInfo.macAddress = address;
        bleInfo.useScanUUIDs = false
        digitalKey.bleInfo = bleInfo
        digitalKey._keyMessageManager = MockKeyMessageManager(uid: self.uid, vin: vehicle.vin ?? "", cardNo: digitalKey.cardNo)

        DispatchQueue.main.async { [weak self] in
            self?.repareBleInfo()
            self?.delegate?.didLoadKeys?(vin: self?.vehicle.vin)
        }
    }

    func setDigitalKeyList(digitalKeyList: [DigitalKey]) {
        Log.i("更新数字钥匙列表：", digitalKeyList)
        if (digitalKeyList.count > 0) {
            self.digitalKeyList = digitalKeyList
        }
    }

    func appendDigitalKey(digitalKey: DigitalKey) -> DigitalKey? {
        let arr = self.digitalMultiKeyArray(keyCardType: digitalKey.keyCardType)
        for key in arr {
            if key.cardNo == digitalKey.cardNo {
                if let index = self.digitalKeyList.firstIndex(of: key) {
                    self.digitalKeyList.remove(at: index) // 删除旧钥匙
                }
            }
        }
        self.digitalKeyList.append(digitalKey)
        Log.i(tag:"DigitalKeyManager", "  数字钥匙报文剩余:", digitalKey.keyMessageCount() )

        return digitalKey
    }

    func repareBleInfo() {
        var bleInfo: BLEInfo? = nil
        if self.digitalKey(keyCardType: .SELF) != nil {
            bleInfo = self.digitalKey(keyCardType: .SELF)!.bleInfo
        } else if self.digitalKey(keyCardType: .CERT) != nil {
            bleInfo = self.digitalKey(keyCardType: .CERT)!.bleInfo
        } else if self.digitalKey(keyCardType: .SAFE) != nil {
            bleInfo = self.digitalKey(keyCardType: .SAFE)!.bleInfo
        } else if self.digitalKey(keyCardType: .MONA_BLE) != nil {
            bleInfo = self.digitalKey(keyCardType: .MONA_BLE)!.bleInfo
        } else if self.digitalKey(keyCardType: .SELF_V3) != nil {
            bleInfo = self.digitalKey(keyCardType: .SELF_V3)!.bleInfo
        }
        Log.i(tag:"DigitalKeyManager", "设置数字钥匙BLEInfo: ", bleInfo ?? "<Null>")
        if (self.bleInfo != bleInfo) {
            self.bleInfo = bleInfo
        }
    }

    // 从数据库中加载该车辆所有的数字钥匙，请求云端数据
    func loadAllDigitalKey(uid: UInt64!, isFromInit: Bool!) {
        Log.i(tag:"DigitalKeyManager", "数字钥匙加载 vin: ", self.vehicle.vin ?? "")
        if (self.vehicle.vin!.count > 0) {
            // 暂时使用同步加载数据库，不然会出现UI层车辆切换完毕但是钥匙还未Ready，激活按钮状态不对的问题
            let digitalKeyList = DigitalKey.queryDigitalKeyList(vin: self.vehicle.vin ?? "")
            Log.i(tag:"DigitalKeyManager", "数字钥匙加载缓存结果(\(digitalKeyList.count)): ", digitalKeyList)
            setDigitalKeyList(digitalKeyList: digitalKeyList)
            if let validKey = validBlePrivateKey(){
                self.bleInfo = validKey.bleInfo
            }
            DispatchQueue.main.async { [weak self] in
                self?.repareBleInfo()
                self?.delegate?.didLoadKeys?(vin: self?.vehicle.vin)
                self?.requestRemoteKeyList(isFromInit: isFromInit)
            }
        }
    }

    func requestRemoteKeyList(isFromInit: Bool) {
        DigitalKeyManager.requestDigitalKeyList(uid: uid, vehicle: self.vehicle, vin: self.vehicle.vin ?? "", vehiclePreference: self.vehiclePreference) { data in
            self.dealWithRemoteKeys(cards: data?.cardList ?? [], isFromInit: isFromInit, localBleInfoOutsideSDK: nil, noBioVerify: nil, doublesidedAuthCode: nil)
            if let jsonData = try? JSONEncoder().encode(data),
               let jsonDict = try? JSONSerialization.jsonObject(with: jsonData, options: []) as? [String: Any] {
                ProxyManger.shared.dbProxy?.refreshDigitalKeyList?(dataList: jsonDict, uid: self.uid, vin: self.vehicle.vin)
            }

            guard let cardList = data?.cardList else {
                self.carKeyPlugin?.remoteCarKeyChanged(keyIdList: nil, uid: self.uid)
                return
            }
            var keyIdList: [String] = [String]()
            for card in cardList {
                if card.cardType == .CCC {
                    keyIdList.append(card.cardNo ?? "")
                }
            }
            if keyIdList.count == 0 {
                self.carKeyPlugin?.remoteCarKeyChanged(keyIdList: nil, uid: self.uid)
            } else {
                self.carKeyPlugin?.remoteCarKeyChanged(keyIdList: keyIdList, uid: self.uid)
            }
        } failed: { error in
            self.failLoadRemoteDigitalKeyList()
            guard self.bleInfo == nil else {
                return
            }
            self.fetchMac()
        }
    }

    func failLoadRemoteDigitalKeyList() {
        if self.digitalKeyList.count == 0{
            if let keys = ProxyManger.shared.dbProxy?.readDigitalKeyList?() {
                let cardInfo: BleCardInfo = decodeToModel(dictionary: keys, to: BleCardInfo.self) ?? BleCardInfo()
                let keyList: [BLEKeyCard]? = cardInfo.cardList ?? []
                if keyList?.count ?? 0 > 0 {
                    self.dealWithRemoteKeys(cards: keyList ?? [], isFromInit: true, localBleInfoOutsideSDK: cardInfo.bleInfo, noBioVerify: cardInfo.noBioVerify, doublesidedAuthCode: cardInfo.doublesidedAuthCode)
                }
                Log.i("钥匙数据的迁移", "获取到APP旧数据，保存至 sdk 2.0 数据库，钥匙数目\(cardInfo.cardList?.count)个")
            } else {
                Log.i("钥匙数据的迁移", "APP旧数据为空")
            }
        }
    }

    func decodeToModel<T: Codable>(dictionary: [String: Any], to type: T.Type) -> T? {
        let jsonData = try? JSONSerialization.data(withJSONObject: dictionary, options: [])
        return jsonData.flatMap { try? JSONDecoder().decode(T.self, from: $0) }
    }

    func dealWithRemoteKeys(cards: [BLEKeyCard]!, isFromInit: Bool!, localBleInfoOutsideSDK: BLEInfo?, noBioVerify:Int?, doublesidedAuthCode: String?) {
        var allKey: [DigitalKey]! = []
        for localKey in self.digitalKeyList ?? []{
            var isFound = false
            for remoteKey in cards {
                if localKey.cardNo == remoteKey.cardNo && localKey.keyCardType == remoteKey.cardType {
                    isFound = true
                    break
                }
                if localKey.keyCardType == .MONA_BLE && remoteKey.cardType == .MONA_BLE, localKey.vin == remoteKey.vin {
                    isFound = true
                    break
                }
            }
            if isFound == false {
                localKey.removeAllKeyMessages()
                localKey.remove()
                var index = 0
                for key: DigitalKey in self.digitalKeyList {
                    let isSupportCarControl = key.isSupportMultiKey()
                    if ((!isSupportCarControl && key.keyCardType == localKey.keyCardType) ||
                        isSupportCarControl && key.cardNo == localKey.cardNo)
                        {
                        self.digitalKeyList.remove(at: index)
                        break;
                    }
                    index = index + 1
                }
                self.repareBleInfo()
                self.delegate?.didRemoveKey?(vin: self.vehicle.vin, keyCardType: localKey.keyCardType, success: true)
            }
        }

        for remoteKey in cards {
            var isFound = false
            var targetKey: DigitalKey?
            for localKey in self.digitalKeyList {

                if (localKey.keyCardType == .MONA_BLE && remoteKey.cardType == .MONA_BLE) ||

                (localKey.cardNo == remoteKey.cardNo && localKey.keyCardType == remoteKey.cardType)
                {
                    isFound = true
                    localKey.bleKeyCard = remoteKey
                    localKey.save()
                    allKey .append(localKey)
                    targetKey = localKey
                    break
                }
            }
            if isFound == false {
                let digitalKey = DigitalKey(bleKeyCard: remoteKey, uid:self.uid, vin: remoteKey.vin ?? "", keyCardType: remoteKey.cardType ?? KeyCardType.NONE, cardNo: remoteKey.cardNo)
                digitalKey.doublesidedAuthCode = doublesidedAuthCode
                digitalKey.bleKeyCard = remoteKey
                if digitalKey.keyCardType == KeyCardType.SAFE {
                    if ProxyManger.shared.dbProxy?.checkKeyExist?(cardNo: digitalKey.cardNo) == true {
                        digitalKey.isRegisterInThisInstall = true
                    }
                    if noBioVerify == 1 {
                        digitalKey.noBioVerfy = true
                    } else {
                        digitalKey.noBioVerfy = false
                    }
                }
                digitalKey.save()
                targetKey = self.appendDigitalKey(digitalKey: digitalKey)
            }
            if targetKey?.supportKeyMessage() == true {
                targetKey?.downloadKeyMessages(callBack: { isSuc in
                    if targetKey?.supportDoublesidedAuth() == true && targetKey?.doublesidedAuthCode == nil {
                        self.downloadDoubleSideCode { isSuc, code in
                            if isSuc == true {
                                targetKey?.doublesidedAuthCode = code
                                targetKey?.save()
                            }
                            self.downloadMacAddress(cards: cards, targetKey: targetKey, isFromInit: isFromInit, localBleInfoOutsideSDK: localBleInfoOutsideSDK)
                        }
                    } else {
                        self.downloadMacAddress(cards: cards, targetKey: targetKey, isFromInit: isFromInit, localBleInfoOutsideSDK: localBleInfoOutsideSDK)
                    }
                })
            } else {
                self.downloadMacAddress(cards: cards, targetKey: targetKey, isFromInit: isFromInit, localBleInfoOutsideSDK: localBleInfoOutsideSDK)
            }
        }
    }

    func downloadMacAddress(cards: [BLEKeyCard]!, targetKey: DigitalKey?, isFromInit: Bool!, localBleInfoOutsideSDK: BLEInfo?) {
        if targetKey?.isNeedMacAddress() == false {
            self.finishLoadKeys(cards: cards)
            return;
        }
        if isFromInit == false {
            if let bleInfo = targetKey?.bleInfo {
                if bleInfo.macAddress != nil {
                    self.finishLoadKeys(cards: cards)
                    return;
                }
            }
        }
        let responseCallback: BLEKeyHttpRequestCallback<BLEInfo> = { response in
            if (response.code == 200 && response.data != nil) {
                let info = response.data!
                self.receiveMacAddress(info: info, isLocal: false, targetKey: targetKey)
            } else {
                if localBleInfoOutsideSDK != nil {
                    self.receiveMacAddress(info: localBleInfoOutsideSDK ?? BLEInfo(), isLocal: true, targetKey: targetKey)
                } else {
                    if let digitalKey: DigitalKey = self.validBlePrivateKey() {
                        if digitalKey.bleInfo?.macAddress != nil {
                            self.bleInfo = digitalKey.bleInfo
                        } else {
                            self.fetchMac()
                        }
                    } else {
                        self.fetchMac()
                    }
                }
            }
            self.finishLoadKeys(cards: cards)
        }
        BLEKeyHttpRequest.postRequest(path: BLEKeyHttpRequestPath.bleInfo, payload: ["vin": targetKey?.vin ?? ""], callback: responseCallback)
    }

    func receiveMacAddress(info :BLEInfo, isLocal: Bool, targetKey: DigitalKey?) {
        let macAddress = (info.macAddress ?? "") as String
        let preText = isLocal == true ? "app旧版" : "下载到"
        Log.i(tag:"DigitalKeyManager", "\(preText)Mac地址 macAddress:", macAddress)
        if (self.vehicle.vehicleTypeCode != "ED") {
            info.useScanUUIDs = true
        }
        targetKey?.bleInfo = info
        self.bleInfo = info
        targetKey?.save()
        let klist = DigitalKey.queryDigitalKeyList(vin: targetKey?.vin ?? "")
        Log.i(tag:"DigitalKeyManager", "数字钥匙写入后加载结果: ", klist)
    }

    func downloadDoubleSideCode(callBack: @escaping (_ isSuc: Bool, _ code: String?) -> Void) {
        let responseCallback: BLEKeyHttpRequestCallback<requestVehicleVerifyCodeResponse> = { verifyResponse in
            guard verifyResponse.code == 200 else {
                callBack(false, nil)
                return
            }
            if let data: requestVehicleVerifyCodeResponse = verifyResponse.data {
                callBack(true, data.verifyCodes.phoneCode.code)
            } else {
                callBack(false, nil)
            }
        }
        BLEKeyHttpRequest.postRequest(path: BLEKeyHttpRequestPath.requestVehicleVerifyCode, payload:["typeList":[1, 2],"vin":self.vehicle.vin ?? ""],callback: responseCallback)
    }

