    public func requestKeySettings(vin: String, device: String?, success: @escaping VehicleDigitalKeySuccessResponseCallback<KeySettingInfo>, failed: @escaping VehicleFailedCallback<VehicleError>) {
        guard !vin.isEmpty else {
            let emptyError = VehicleError(code: -1, desc: "vin参数不能为空")
            failed(emptyError)
            return
        }
        var param: [String : Any] = ["vin":vin,
                     "platformType": 1,
                     "bizKey":"POLLING"]
        if let device = device {
            param["deviceModel"] = device
        }
        Log.i(tag:"DigitalKeyManager", "kkl param:", param)

        BLEKeyHttpRequest.getRequest(path: BLEKeyHttpRequestPath.getPollingSettingV2, payload: param) {(response: VehicleRequestResponse<KeySettingInfo>) in
            if response.code == 200, let data = response.data {
                success(data)
            } else {
                let resp = VehicleError(code: response.code, desc: response.msg)
                failed(resp)
            }
        }
    }

    public func uploadKeySettings(vin: String, device: String?, settings: KeySettingInfo, success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>) {
        guard !vin.isEmpty else {
            let emptyError = VehicleError(code: -1, desc: "vin参数不能为空")
            failed(emptyError)
            return
        }

        var param = ["vin":vin,
                     "platformType": 1,
                     "bizKey":"POLLING"] as [String : Any]
        if let device = device {
            param["deviceModel"] = device
        }
        param["bizValue"] = settings.toDictionary()
        BLEKeyHttpRequest.postRequest(path: BLEKeyHttpRequestPath.uploadPollingSettingV2, payload: param) {(response: VehicleRequestResponse<Bool>) in
            if response.code == 200 && response.data == true {
                success()
            } else {
                let resp = VehicleError(code: response.code, desc: response.msg)
                failed(resp)
            }
        }
    }

    static func allowCallMonaSDK(vehiclePreference: VehiclePreference) -> Bool {
        return vehiclePreference.function.POLLING_STRATEGY_D01_BAN == true
    }

    static func isBleKeyV3(vehiclePreference: VehiclePreference) -> Bool {
        return vehiclePreference.abilityConfig.bleKeyVersion == BleKeyProtocolVesion.V3
    }

    @objc func connectStateChanged(noti: Notification)  {
        Log.i(tag: "connectStateChanged", "ii收到蓝牙连接状态变更通知 userinfo:\(noti.userInfo)")
        guard let obj: BLEConnectionNotiObject = noti.userInfo?["state"] as? BLEConnectionNotiObject else { return }
        if obj.vin == self.vehicle.vin && obj.connectState == BLEConnectionState.Available {
            isTboxBad = false
            Log.i(tag: "connectStateChanged", " isTboxBad:\(isTboxBad)")
            if let key = self.validBlePrivateKey(), let plugin = self.createPlugin(keyCardType: key.keyCardType) {
                plugin.clearWaitToActivate()
            }
        }
    }

    @objc func tboxRunStateNotification(noti: Notification)  {
        Log.i(tag: "tboxRunStateNotification", "收到TBOX状态变更通知 userinfo:\(noti.userInfo)")
        isTboxBad = noti.userInfo?["result"] as? Int ?? 0 != 0
    }

    @objc func networkResumeAction() {
        if let digitalKey: DigitalKey = self.validBlePrivateKey() {
            guard digitalKey.supportKeyMessage() == true else {
                return
            }
            digitalKey.downloadKeyMessages { isSuc in
                Log.i(tag:"DigitalKeyManager", "网络恢复，触发报文数检查(量足则不拉)", isSuc)
            }
            guard self.bleInfo == nil else {
                return
            }
            self.requestMacAddressOnce(currentVin: digitalKey.vin ?? "") { isSuc in
                Log.i(tag:"DigitalKeyManager", "网络恢复，尝试拉mac", isSuc)
                guard isSuc == false else {
                    return
                }
                self.fetchMac()
            }
        }
    }

    public func setDigitalKeySwitch(lockParam: CarKeyAutoLockRequestParam, vin: String, uid: UInt64, success:  ((Bool) -> Void)? = nil, failed: ((VehicleError) -> Void)? = nil) {
        guard let plugin = self.createPlugin(keyCardType: KeyCardType.CCC) else {
            failed?(VehicleError(code: .NotSupported, desc: "尚未支持，操作失败"))
            return
        }
        plugin.setDigitalKeySwitch(lockParam: lockParam, vin: vin, uid: uid, success: { result in
            success?(result ?? true)
        }, failed: { error in
            failed?(error)
        })
    }

    func setIsDriverMode(_ isDriverMode: Bool) {
        if let xiaopengBleConnection = self.communication?.bleConnection as? XiaopengBLEConnection {
            xiaopengBleConnection.getKeySettingData().isDriverMode = isDriverMode
            xiaopengBleConnection.bleSwitcheCheck.needDisconnectInBackground = !isDriverMode
        }
    }

    func getCurrentCarKeyPlugin() -> CarKeyPassAccessProtocol? {
        return self.carKeyPlugin
    }

}

