13	    XPBlueToothCentralUnknown         = CBManagerStateUnknown,
14	    XPBlueToothCentralResetting       = CBManagerStateResetting,
15	    XPBlueToothCentralUnsupported     = CBManagerStateUnsupported,
16	    XPBlueToothCentralUnauthorized    = CBManagerStateUnauthorized,
17	    XPBlueToothCentralPoweredOff      = CBManagerStatePoweredOff,
