21	@interface XPBluetoothConnectInfo : NSObject
22	{
23	    dispatch_semaphore_t _lock;
24	    CBPeripheral* _peripheral;
25	}
26	@property (nonatomic,strong,setter=setupPeripheral:,getter=getPeripheral) CBPeripheral* peripheral;
