33	- (BOOL)discoverFilter:(NSString*)peripheralName advertisementData:(NSDictionary*)advertisementData RSSI:(NSNumber*)RSSI;
34	- (BOOL)connectFilter:(NSString*)peripheralName advertisementData:(NSDictionary*)advertisementData RSSI:(NSNumber*)RSSI;
35	@end
36	
37	NS_INLINE NSString* CBCharacteristicPropertiesToString(CBCharacteristicProperties p) {
38	    NSMutableArray* array = [NSMutableArray arrayWithCapacity:12];
39	    if (p&CBCharacteristicPropertyBroadcast) {
40	        [array addObject:@"CBCharacteristicPropertyBroadcast"];
41	    }
42	    
43	    if (p&CBCharacteristicPropertyRead) {
44	        [array addObject:@"CBCharacteristicPropertyRead"];
45	    }
46	    
47	    if (p&CBCharacteristicPropertyWriteWithoutResponse) {
48	        [array addObject:@"CBCharacteristicPropertyWriteWithoutResponse"];
49	    }
50	    
51	    if (p&CBCharacteristicPropertyWrite) {
52	        [array addObject:@"CBCharacteristicPropertyWrite"];
53	    }
54	    
55	    if (p&CBCharacteristicPropertyNotify) {
56	        [array addObject:@"CBCharacteristicPropertyNotify"];
57	    }
58	    
59	    if (p&CBCharacteristicPropertyIndicate) {
60	        [array addObject:@"CBCharacteristicPropertyIndicate"];
61	    }
62	    
63	    if (p&CBCharacteristicPropertyAuthenticatedSignedWrites) {
64	        [array addObject:@"CBCharacteristicPropertyAuthenticatedSignedWrites"];
65	    }
66	    
67	    if (p&CBCharacteristicPropertyExtendedProperties) {
68	        [array addObject:@"CBCharacteristicPropertyExtendedProperties"];
69	    }
70	    
71	    if (p&CBCharacteristicPropertyExtendedProperties) {
72	        [array addObject:@"CBCharacteristicPropertyExtendedProperties"];
73	    }
74	    
75	    if (p&CBCharacteristicPropertyNotifyEncryptionRequired) {
76	        [array addObject:@"CBCharacteristicPropertyNotifyEncryptionRequired"];
77	    }
78	    if (p&CBCharacteristicPropertyIndicateEncryptionRequired) {
79	        [array addObject:@"CBCharacteristicPropertyIndicateEncryptionRequired"];
80	    }
81	    
82	    return [array componentsJoinedByString:@"|"];
83	}
84	
85	NS_INLINE NSString* NSStringFromCBPeripheralState(CBPeripheralState state) {
86	    switch (state) {
87	        case CBPeripheralStateDisconnected:
88	            return @"CBPeripheralStateDisconnected";
89	            break;
90	        case CBPeripheralStateConnecting:
91	            return @"CBPeripheralStateConnecting";
92	            break;
93	        case CBPeripheralStateConnected:
94	            return @"CBPeripheralStateConnected";
95	            break;
96	        case CBPeripheralStateDisconnecting:
97	            return @"CBPeripheralStateDisconnecting";
98	            break;
99	        default:
100	            break;
101	    }
102	    
103	    return @"Unknow";
104	}
105	
106	NS_INLINE NSString* NSStringFromXPBluetoothCentralState(XPBluetoothCentralState state) {
107	    switch (state) {
108	        case XPBlueToothCentralUnknown:
109	            return @"XPBlueToothCentralUnknown";
110	            break;
111	        case XPBlueToothCentralResetting:
112	            return @"XPBlueToothCentralResetting";
113	            break;
114	        case XPBlueToothCentralUnsupported:
