NS_INLINE NSString* CBCharacteristicPropertiesToString(CBCharacteristicProperties p) {
    NSMutableArray* array = [NSMutableArray arrayWithCapacity:12];
    if (p&CBCharacteristicPropertyBroadcast) {
        [array addObject:@"CBCharacteristicPropertyBroadcast"];
    }

    if (p&CBCharacteristicPropertyRead) {
        [array addObject:@"CBCharacteristicPropertyRead"];
    }

    if (p&CBCharacteristicPropertyWriteWithoutResponse) {
        [array addObject:@"CBCharacteristicPropertyWriteWithoutResponse"];
    }

    if (p&CBCharacteristicPropertyWrite) {
        [array addObject:@"CBCharacteristicPropertyWrite"];
    }

    if (p&CBCharacteristicPropertyNotify) {
        [array addObject:@"CBCharacteristicPropertyNotify"];
    }

    if (p&CBCharacteristicPropertyIndicate) {
        [array addObject:@"CBCharacteristicPropertyIndicate"];
    }

    if (p&CBCharacteristicPropertyAuthenticatedSignedWrites) {
        [array addObject:@"CBCharacteristicPropertyAuthenticatedSignedWrites"];
    }

    if (p&CBCharacteristicPropertyExtendedProperties) {
        [array addObject:@"CBCharacteristicPropertyExtendedProperties"];
    }

    if (p&CBCharacteristicPropertyExtendedProperties) {
        [array addObject:@"CBCharacteristicPropertyExtendedProperties"];
    }

    if (p&CBCharacteristicPropertyNotifyEncryptionRequired) {
        [array addObject:@"CBCharacteristicPropertyNotifyEncryptionRequired"];
    }
    if (p&CBCharacteristicPropertyIndicateEncryptionRequired) {
        [array addObject:@"CBCharacteristicPropertyIndicateEncryptionRequired"];
    }

    return [array componentsJoinedByString:@"|"];
}

NS_INLINE NSString* NSStringFromCBPeripheralState(CBPeripheralState state) {
    switch (state) {
        case CBPeripheralStateDisconnected:
            return @"CBPeripheralStateDisconnected";
            break;
        case CBPeripheralStateConnecting:
            return @"CBPeripheralStateConnecting";
            break;
        case CBPeripheralStateConnected:
            return @"CBPeripheralStateConnected";
            break;
        case CBPeripheralStateDisconnecting:
            return @"CBPeripheralStateDisconnecting";
            break;
        default:
            break;
    }

    return @"Unknow";
}

NS_INLINE NSString* NSStringFromXPBluetoothCentralState(XPBluetoothCentralState state) {
    switch (state) {
        case XPBlueToothCentralUnknown:
            return @"XPBlueToothCentralUnknown";
            break;
        case XPBlueToothCentralResetting:
            return @"XPBlueToothCentralResetting";
            break;
        case XPBlueToothCentralUnsupported:
            return @"XPBlueToothCentralUnsupported";
            break;
        case XPBlueToothCentralUnauthorized:
            return @"XPBlueToothCentralUnauthorized";
            break;
        case XPBlueToothCentralPoweredOff:
            return @"XPBlueToothCentralPoweredOff";
            break;
        case XPBlueToothCentralPoweredOn:
            return @"XPBlueToothCentralPoweredOn";
            break;
        default:
            break;
    }
    return @"XPBlueToothCentralUnknown";
}

