- (void)writeVehicleExtensionInfoWithData:(NSDictionary<NSString *,id> * _Nonnull)data vin:(NSString * _Nonnull)vin { 

}

- (NSDictionary<NSString *,id> * _Nullable)readDigitalKeyList {
    NSArray<XPBLEKeyCard *> *cardList = self.allCardList;
    NSMutableArray *tempArray = [NSMutableArray array];
    for (XPBLEKeyCard *card in cardList) {
        if (XPVehicleSDK.currentAbilityConfig.bleKeyVersion == BleKeyProtocolVesionV3 && card.cardType == XPBLEKeyCardType_BLESelfKey) {
            card.cardType = XPBLEKeyCardType_V3_XPBLE_PhoneKey;
        }
        [tempArray addObject:card];
    }
    NSArray *carArr = [tempArray yy_modelToJSONObject];
    XPCarBleInfo *ble = CTMediator.defaultCarInfo.bleInfo?:[XPCarBleInfo new];
    NSNumber *noBioVerify = (CTMediator.isE28 && [XPBLEKeyManager instance].isSafeKeyExisted && [XPBLEKeyManager.instance checkIsNoneVerifySettingWithVin:CTMediator.vin]) ? @(1):@(0);
    return @{@"cardList": carArr?:@[], @"bleInfo": [ble yy_modelToJSONObject], @"noBioVerify": noBioVerify,@"doublesidedAuthCode":[XPVehicleVerifyCodeManager.sharedInstance verifyCodesWithVin:CTMediator.vin].phoneCode.code};
}

- (void)refreshDigitalKeyListWithDataList:(NSDictionary<NSString *,id> *)dataList uid:(uint64_t)uid vin:(NSString *)vin {
    NSArray *localCard = [self allCardList];
    for (XPBLEKeyCard *item in localCard) {
        if (dataList) {
            BOOL isFound = NO;
            NSArray<XPBLEKeyCard *> *myKeys = [NSArray yy_modelArrayWithClass:XPBLEKeyCard.class json:dataList[@"cardList"]];
            for (XPBLEKeyCard *newItem in myKeys) {
                if (item.cardNo && [item.cardNo isEqualToString:newItem.cardNo]) {
                    isFound = YES;
                    break;
                }
            }
            if (!isFound) {
                [self deleteCard:item vin:vin];
            }
        } else {
            [self deleteCard:item vin:vin];
        }
    }
    _allCardList = nil;
}

- (void)deleteCard:(XPBLEKeyCard *)card vin:(NSString *)vin {
    if (card) {
        [self deleteMessageWithCardNo:card.cardNo vin:vin];
        [card deleteCard];
    }
}

