    XPCarBleInfo *ble = CTMediator.defaultCarInfo.bleInfo?:[XPCarBleInfo new];
    NSNumber *noBioVerify = (CTMediator.isE28 && [XPBLEKeyManager instance].isSafeKeyExisted && [XPBLEKeyManager.instance checkIsNoneVerifySettingWithVin:CTMediator.vin]) ? @(1):@(0);
    return @{@"cardList": carArr?:@[], @"bleInfo": [ble yy_modelToJSONObject], @"noBioVerify": noBioVerify,@"doublesidedAuthCode":[XPVehicleVerifyCodeManager.sharedInstance verifyCodesWithVin:CTMediator.vin].phoneCode.code};
}

- (void)refreshDigitalKeyListWithDataList:(NSDictionary<NSString *,id> *)dataList uid:(uint64_t)uid vin:(NSString *)vin {
    NSArray *localCard = [self allCardList];
    for (XPBLEKeyCard *item in localCard) {
        if (dataList) {
            BOOL isFound = NO;
            NSArray<XPBLEKeyCard *> *myKeys = [NSArray yy_modelArrayWithClass:XPBLEKeyCard.class json:dataList[@"cardList"]];
            for (XPBLEKeyCard *newItem in myKeys) {
                if (item.cardNo && [item.cardNo isEqualToString:newItem.cardNo]) {
                    isFound = YES;
                    break;
                }
            }
            if (!isFound) {
                [self deleteCard:item vin:vin];
            }
        } else {
            [self deleteCard:item vin:vin];
        }
    }
    _allCardList = nil;
}

- (void)deleteCard:(XPBLEKeyCard *)card vin:(NSString *)vin {
    if (card) {
        [self deleteMessageWithCardNo:card.cardNo vin:vin];
        [card deleteCard];
    }
}

- (void)deleteMessageWithCardNo:(NSString *)cardNo vin:(NSString *)vin {
    if (StringIsEmpty(cardNo) || StringIsEmpty(vin)) {
        return;
    }
    XPBLEKeyCard *safeCard = XPBLEKeyManager.instance.defaultCard;

    if (safeCard && [safeCard isValidInOldCode] && [safeCard.cardNo isEqualToString:cardNo]) {
        NSInteger count = [self getSafeMessageCountWithVin:vin cardNo:cardNo];
        if (count > 0) {
            EtasConfiguration* config = [XPBLEKeyManager createEtasConfiguration:vin cardNo:cardNo];
            EtasGetAuthDataSession* session = [EtasGetAuthDataSession createSessionWithConfig:config];
            [session clearIfaaAuthData];
        }
    } else {
        [CertKeyMessage removeMessageWithVin:vin uid:CTMediator.uid cardNo:cardNo];
    }
}

- (NSString *)getOneCertMessageWithVin:(NSString *)vin cardNo:(NSString *)cardNo {
    for (XPBLEKeyCard *card in self.allCardList) {
        if ([cardNo isEqualToString:card.cardNo]) {
            return [CertKeyMessage getOneMessageWithVin:vin cardNo:cardNo].message;
        }
    }
    return nil;
}

- (void)getOneSafeMessageWithVin:(NSString *)vin cardNo:(NSString *)cardNo callback:(void (^)(NSString * _Nullable message))callback{
    if (StringIsEmpty(vin)) {
        callback(nil);
        return;
    }
    XPBLEKeyCard *card = [self safeKeyCard];
    if (card && [card isValidInOldCode] && [card.cardNo isEqualToString:cardNo]) {
        [[[XPBLEKeyManager.instance.verifyCommand execute:nil] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeNext:^(NSString*  _Nullable ifaaMsg) {
            callback(ifaaMsg);
        } error:^(NSError * _Nullable error) {
            callback(nil);
        }];
    } else {
        callback(nil);
    }
}

- (BOOL)checkKeyExistWithCardNo:(NSString *)cardNo{
    if (StringIsEmpty(cardNo)) {
        return NO;
    }
    for (XPBLEKeyCard* card in self.allCardList) {
        if (card.cardNo && [card.cardNo isEqualToString:cardNo]) {
            return YES;
        }
    }
    return NO;
}

- (XPBLEKeyCard *)safeKeyCard {
    for (XPBLEKeyCard* card in self.allCardList) {
        if (XPBLEKeyCardType_BLEKey == card.cardType) {
            return card;
        }
    }
    return nil;
}

-(NSInteger)getSafeMessageCountWithVin:(NSString *)vin cardNo:(NSString *)cardNo {
    EtasConfiguration* config = [XPBLEKeyManager createEtasConfiguration:vin cardNo:cardNo];
    EtasGetAuthDataSession* session = [EtasGetAuthDataSession createSessionWithConfig:config];
    NSInteger count = [session getRemainIfaaAuthDataCount];
    DLogTagInfo(kBLEKeyTag, @"安全钥匙报文数量: %@", @(count));
    return count;
}

- (NSArray <XPBLEKeyCard*>*)allCardList{
    if (!_allCardList) {
        NSMutableArray *allCards = [NSMutableArray array];
        [allCards addObjectsFromArray:[XPBLEKeyCard localMyOwnCardsWithVin:CTMediator.vin]];
        [allCards addObjectsFromArray:[XPBLEKeyCard localEmpowerCardsWithVin:CTMediator.vin]];
        _allCardList = [NSArray arrayWithArray:allCards];
    }
    return _allCardList;
}

// 读取 App 当前车辆
- (NSString *)readSelectedVehicleVin {
    return [CarPermissionManager defaultCarVinLocal];
}

- (void)writeAppMqttAccountWithMqttAccount:(NSDictionary<NSString *,id> *)mqttAccount {
    MQTTAccount *mqtt = [MQTTAccount yy_modelWithJSON:mqttAccount];
    if (mqtt) {
        [MQTTAccount updateMqttAccount:mqtt];
        [CTMediator loginInfoViewModel].loginInfo.mqttAccount = mqtt;
        [[CTMediator loginInfoViewModel] updateLoginInfo:CTMediator.loginInfoViewModel.loginInfo];
    }
}

- (void)markMonaCreateStepWithMark:(BOOL)mark{
    [XPMonaCreateBLEKeyViewModel markActivateWaitCloseCar:mark];
}

