@import XPVehicleSDK;
@import XPVehicleExt;

#define kResumeKeyCheckFromRestart @"com.xiaopeng.XPKeyCheck.Resume"
#define kResumeCommandKeyCheckFromRestart @"com.xiaopeng.XPKeyCheck.Resume.Command"
#define kResumeSkipAlertKeyCheckFromRestart @"com.xiaopeng.XPKeyCheck.Resume.SkipAlert"
#define kResumeSessionIdKeyCheckFromRestart @"com.xiaopeng.XPKeyCheck.Resume.SessionId"

NSString *const XPKeyCheckErrorDomain = @"com.xiaopeng.XPKeyCheck.Error";

#define kKeyCheckTag @"钥匙检查"

typedef NS_ENUM(NSInteger, XPKeyCheckErrorCode) {
    XPKeyCheckErrorCodeDefault = 0,
    XPKeyCheckErrorCodeNoKey,
    XPKeyCheckErrorCodeFailToCreateKey,
    XPKeyCheckErrorCodePoweredOff,
    XPKeyCheckErrorCodeNoPermission,
    XPKeyCheckErrorCodeNotNearby,
    XPKeyCheckErrorCodeOccupied,
    XPKeyCheckErrorCodeFailToConnect,
    XPKeyCheckErrorCodeFailToAuth,
    XPKeyCheckErrorCodeFailToSend,
    XPKeyCheckErrorCodeFailToExecute,
    XPKeyCheckErrorCodeFailToResetBle,
    XPKeyCheckErrorCodeExecuteTimeout,
    XPKeyCheckErrorCodeKeyError,
    XPKeyCheckErrorCodeRemoteStarted,
    XPKeyCheckErrorCodeRemoteLocked,
    XPKeyCheckErrorCodeGoToFinal,
    XPKeyCheckErrorCodeCancel,
};

typedef NS_ENUM(NSInteger, XPKeyCheckProgress) {
    XPKeyCheckProgressDefault = 0,
    XPKeyCheckProgressCreateKeyChecking,
    XPKeyCheckProgressCreateKeyChecked,
    XPKeyCheckProgressBleStateChecking,
    XPKeyCheckProgressBleStateChecked,
    XPKeyCheckProgressNearbyChecking,
    XPKeyCheckProgressNearbyChecked,
    XPKeyCheckProgressResetBleChecking,
    XPKeyCheckProgressResetBleChecked,
    XPKeyCheckProgressRestartChecking,
    XPKeyCheckProgressRestartChecked,
    XPKeyCheckProgressConnectChecking,
    XPKeyCheckProgressConnectChecked,
    XPKeyCheckProgressCommandChecking,
    XPKeyCheckProgressCommandChecked,
    XPKeyCheckProgressResetKeyChecking,
    XPKeyCheckProgressResetKeyChecked,
};

@interface XPKeyCheckViewController ()

@property (nonatomic, strong) MyCarInfo *carInfo;
@property (nonatomic, strong) XPUIGradientView *bgGradientView;
@property (nonatomic, strong) XPKeyCheckingView *checkingView;
@property (nonatomic, strong) XPKeyCheckSuccessView *successView;
@property (nonatomic, strong) XPKeyCheckFailView *failView;
@property (nonatomic, strong) XPKeyCheckFinalView *finalView;
@property (nonatomic, strong) RACCommand<NSDictionary *,NSNumber *> *checkCommand;
@property (nonatomic, strong) NSMutableArray<XPKeyCheckingCellItem *> *items;
@property (nonatomic, strong) XPCreateKeyViewController *createKeyViewController;
@property (nonatomic, assign, readonly) XPTBoxCommand command;
@property (nonatomic, assign, readonly) BOOL isStart;
@property (nonatomic, assign, readonly) BOOL skipAlert;
@property (nonatomic, assign) uint64_t sessionId;
@property (nonatomic, assign, readonly) NSInteger from;
@property (nonatomic, strong) NSError *currentError;
@property (nonatomic, assign) BOOL isRemoteComplete;
@property (nonatomic, strong) RACSubject *viewDidAppearSubject;
@property (nonatomic, strong) RACSubject *bleConnectStateSubject;
@property (nonatomic, strong) RACReplaySubject *sysBleStateSubject;
@property (nonatomic, strong) XPBleCheckManager *bleCheckManager;
@end

@implementation XPKeyCheckViewController

+ (BOOL)resumeFromRestart{
    return [MMKV.defaultMMKV getBoolForKey:kResumeKeyCheckFromRestart defaultValue:NO];
}

+ (void)markResumeFromRestart:(BOOL)resume{
    [MMKV.defaultMMKV setBool:resume forKey:kResumeKeyCheckFromRestart];
}

+ (uint8_t)resumeCommand{
    return [MMKV.defaultMMKV getUInt32ForKey:kResumeCommandKeyCheckFromRestart];
}

+ (void)markResumeCommand:(uint8_t)cmd{
    [MMKV.defaultMMKV setUInt32:cmd forKey:kResumeCommandKeyCheckFromRestart];
}

+ (BOOL)resumeSkipAlert{
    return [MMKV.defaultMMKV getBoolForKey:kResumeSkipAlertKeyCheckFromRestart defaultValue:NO];
}

+ (void)markSkipAlert:(BOOL)skipAlert{
    [MMKV.defaultMMKV setBool:skipAlert forKey:kResumeSkipAlertKeyCheckFromRestart];
}

+ (uint64_t)resumeSessionId{
    return [MMKV.defaultMMKV getUInt64ForKey:kResumeSessionIdKeyCheckFromRestart];
}

+ (void)markResumeSessionId:(uint64_t)sessionId{
    [MMKV.defaultMMKV setUInt64:sessionId forKey:kResumeSessionIdKeyCheckFromRestart];
}

- (void)dealloc{
    DLogTagInfo(kBLEKeyTag, @"dealloc");
}

- (instancetype)init{
    self = [super init];
    if (self) {
        _sessionId = (uint64_t)([[NSDate date] timeIntervalSince1970] * 1000);
        _viewDidAppearSubject = [RACSubject subject];
        _bleConnectStateSubject = [RACSubject subject];
        _sysBleStateSubject = [RACReplaySubject replaySubjectWithCapacity:1];
    }
    return self;
}

- (void)setupNav {
    self.fd_prefersNavigationBarHidden = YES;

    XPCommonNavigationBar *textBar = [[XPCommonNavigationBar alloc] initWithFrame:CGRectMake(0, 0, SCREEN_WIDTH, kTopBarHeight)];
    textBar.layer.zPosition = 999;
    [textBar setTitle:@"钥匙检查与启动"];
    textBar.titleLabel.font = [UIFont xp_titleRegularFont];
    textBar.backgroundColor = UIColorClear;
    [self.view addSubview:textBar];
}

- (void)loadView{
    [super loadView];
    [self setupNav];

    UIImageView *bgImageView = [UIImageView new];
    [self.view insertSubview:bgImageView atIndex:0];
    [bgImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.top.mas_equalTo(0);
        make.height.mas_equalTo(500*AdaptiveRatio);
    }];

    [self.view insertSubview:self.bgGradientView atIndex:0];
    [self.bgGradientView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.top.mas_equalTo(0);
        make.height.mas_equalTo(500*AdaptiveRatio);
    }];

    [self.contentView addSubview:self.checkingView];
    [self.checkingView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.mas_equalTo(0);
    }];

    [self.contentView addSubview:self.successView];
    [self.successView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.mas_equalTo(0);
    }];

    [self.contentView addSubview:self.failView];
    [self.failView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.mas_equalTo(0);
    }];

    [self.contentView addSubview:self.finalView];
    [self.finalView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.mas_equalTo(0);
    }];

    [self updateViewWithTheme];
}

- (XPTBoxCommand)command{
    XPTBoxCommand result = [self.params[@"command"] unsignedShortValue];
    if(result == 0) result = XPTBoxCommandUnlock;
    return result;
}

- (uint64_t)sessionId{
    uint64_t sessionId = [self.params[@"sessionId"] unsignedLongLongValue];
    if(sessionId != 0) return sessionId;
    return _sessionId;
}

- (NSInteger)from{
    NSInteger from = [self.params[@"from"] integerValue];
    if(from == 0) return 4;
    return from;
}

- (BOOL)skipAlert{
    BOOL skipAlert = [self.params[@"skipAlert"] boolValue];
    return skipAlert;
}

- (BOOL)isStart{
    return self.carInfo.isE28 || self.carInfo.isD22;
}

- (BOOL)remoteStartIsSupported{
    return self.carInfo.isSupportRemoteStart;
}

- (void)qmui_themeDidChangeByManager:(QMUIThemeManager *)manager identifier:(__kindof NSObject<NSCopying> *)identifier theme:(__kindof NSObject *)theme{
    [super qmui_themeDidChangeByManager:manager identifier:identifier theme:theme];
    [self updateViewWithTheme];
}

- (void)updateViewWithTheme{
    BOOL isDark = [[QMUIThemeManagerCenter defaultThemeManager].currentThemeIdentifier isEqual:XPThemeIdentifierDark];
    if(isDark){
        [self.bgGradientView setGradientBackgroundWithColors:@[[UIColor colorWithHexValue:0x0E0F14], [UIColor xp_baseBackgroundColor]] locations:@[@0, @1] startPoint:CGPointMake(0.5, 0) endPoint:CGPointMake(0.5, 1)];
    }else{
        [self.bgGradientView setGradientBackgroundWithColors:@[[UIColor colorWithHexValue:0xD7E0F1], [UIColor xp_baseBackgroundColor]] locations:@[@0, @1] startPoint:CGPointMake(0.5, 0) endPoint:CGPointMake(0.5, 1)];
    }
}

- (void)viewDidLoad {
    [super viewDidLoad];
    self.view.backgroundColor = [UIColor xp_baseBackgroundColor];

    [self addBleConnectStateObserver];

    [self.class markResumeFromRestart:NO];

    self.carInfo = CTMediator.defaultCarInfo;
    if(!(self.carInfo.hasBleAbility && !self.carInfo.carFunction.WITHOUT_BLE)){
        DLogTagInfo(kBLEKeyTag, @"车辆不支持蓝牙钥匙");
        [XPToast showMessage:@"当前车辆不支持手机钥匙"];
        [self.navigationController popViewControllerAnimated:YES];
        return;
    }

    self.bleCheckManager = [XPVehicleExt createBleCheckManager:XPVehicleSDK.shared.vehicleManager.currentVehicle];

    @weakify(self);
    [self.rac_deallocDisposable addDisposable:[CTMediator.defaultCarSwitchedSignal.deliverOnMainThread subscribeNext:^(MyCarInfo * _Nullable x) {
        @strongify(self);
        if(![x.vin isEqualToString:self.carInfo.vin]){
            [XPToast showMessage:@"车辆切换，退出检查"];
            [self.navigationController popViewControllerAnimated:YES];
        }
    }]];

    [self.rac_deallocDisposable addDisposable:[self.checkingView.finalSubject subscribeNext:^(id _Nullable x) {
        @strongify(self);
        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_EMERGENCY_KEY module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
        [self popToWifiViewController];
    }]];

    [self.rac_deallocDisposable addDisposable:[self.checkingView.callSubject subscribeNext:^(id _Nullable x) {
        @strongify(self);
        [self contactCustomerService];
    }]];

    [self.rac_deallocDisposable addDisposable:[[self.checkingView.stopButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
        @strongify(self);
        [self.navigationController popViewControllerAnimated:YES];
    }]];

    [self.rac_deallocDisposable addDisposable:[[self.successView.backButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
        @strongify(self);
        [self.navigationController popViewControllerAnimated:YES];
    }]];

    [self.rac_deallocDisposable addDisposable:[self.failView.finalSubject subscribeNext:^(id _Nullable x) {
        @strongify(self);
        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_EMERGENCY_KEY module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
        [self popToWifiViewController];
    }]];

    [self.rac_deallocDisposable addDisposable:[self.failView.callSubject subscribeNext:^(id _Nullable x) {
        @strongify(self);
        [self contactCustomerService];
    }]];

    [self.rac_deallocDisposable addDisposable:[[self.failView.nextButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
        @strongify(self);
        switch (self.currentError.code) {
            case XPKeyCheckErrorCodePoweredOff:
            {
                if([self isPoweredOn]){
                    [self restartCheck];
                }else{
                    XPBleGuideViewController *vc = [XPBleGuideViewController new];
                    [vc showInViewController:self];
                }
            }
                break;
            case XPKeyCheckErrorCodeNoPermission:
            {
                NSURL *url = [NSURL URLWithString:UIApplicationOpenSettingsURLString];
                if([UIApplication.sharedApplication canOpenURL:url]) [UIApplication.sharedApplication openURL:url options:@{} completionHandler:^(BOOL success) {}];
            }
                break;
            default:
                [self restartCheck];
                break;
        }
    }]];

    [self.rac_deallocDisposable addDisposable:[[self.failView.backButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
        @strongify(self);
        [self.navigationController popViewControllerAnimated:YES];
    }]];

    [self.rac_deallocDisposable addDisposable:[self.finalView.finalSubject subscribeNext:^(id _Nullable x) {
        @strongify(self);
        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_EMERGENCY_KEY module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
        [self popToWifiViewController];
    }]];

    [self.rac_deallocDisposable addDisposable:[self.finalView.callSubject subscribeNext:^(id _Nullable x) {
        @strongify(self);
        [self contactCustomerService];
    }]];

    [self.rac_deallocDisposable addDisposable:[[self.finalView.backButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
        @strongify(self);
        [self.navigationController popViewControllerAnimated:YES];
    }]];

    [self.rac_deallocDisposable addDisposable:[[self.finalView.nextButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
        @strongify(self);
        if([self wifiKeySupported]){
            [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_EMERGENCY_KEY module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
            [self popToWifiViewController];
        }else{
            [self restartCheck];
        }
    }]];

    if(![self.params[@"resume"] boolValue]){
        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_ENTRY module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId), @"from": @(self.from)}];
    }

    //如果数字钥匙3.0，开通了钱包钥匙,那就不归App控制了
    if ([XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager vaildBleKeyCategory] == XPDigitalKeyCategoryPHONE_UWB_KEY) {
        [QMUIAlertController showAlertWithTitle:@"如遇手机钥匙无法连接车辆，请查看钥匙状态是否正常"
                                        message:@""
                               leftButtionTitle:@"关闭"
                                 leftButtonType:QMUIAlertActionStyleCancel
                                     leftAction:^(__kindof QMUIAlertController * _Nonnull alertVC, QMUIAlertAction * _Nonnull action) {
            @strongify(self);
            [self.navigationController popViewControllerAnimated:YES];
        }
                               rightButtonTitle:@"查看钥匙状态"
                                rightButtonType:QMUIAlertActionStyleDefault
                                    rightAction:^(__kindof QMUIAlertController * _Nonnull alertVC, QMUIAlertAction * _Nonnull action) {
            [XPCarKeyHelp.shared openCarKeyPass];
            [self.navigationController popViewControllerAnimated:YES];
        }];
        return;
    }

    [self startCheck];
}

- (void)viewDidAppear:(BOOL)animated{
    [super viewDidAppear:animated];
    [self.viewDidAppearSubject sendNext:nil];
}

- (void)viewDidDisappear:(BOOL)animated{
    [super viewDidDisappear:animated];
}

- (void)restartCheck{
    NSMutableDictionary *params = self.params.mutableCopy;
    params[@"resume"] = @NO;
    self.params = [NSDictionary dictionaryWithDictionary:params];
    [self startCheck];
}

- (void)startCheck{
    @weakify(self);
    [[self.checkCommand execute:self.params?:@{}].deliverOnMainThread subscribeNext:^(NSNumber * _Nullable x) {
        @strongify(self);
        [self updateView];
        self.checkingView.hidden = NO;
        self.successView.hidden = YES;
        self.failView.hidden = YES;
        self.finalView.hidden = YES;

        XPKeyCheckProgress progress = [x integerValue];
        switch (progress) {
            case XPKeyCheckProgressDefault:
                self.items = [NSMutableArray new];
                break;
            case XPKeyCheckProgressCreateKeyChecking:
                [self makeItemCheckingWithType:XPKeyCheckingCellTypeCreateKey];
                break;
            case XPKeyCheckProgressCreateKeyChecked:
                [self makeItemSuccessWithType:XPKeyCheckingCellTypeCreateKey];
                break;
            case XPKeyCheckProgressBleStateChecking:
                [self makeItemCheckingWithType:XPKeyCheckingCellTypeBleState];
                break;
            case XPKeyCheckProgressBleStateChecked:
                [self makeItemSuccessWithType:XPKeyCheckingCellTypeBleState];
                break;
            case XPKeyCheckProgressNearbyChecking:
                [self makeItemCheckingWithType:XPKeyCheckingCellTypeNearby];
                break;
            case XPKeyCheckProgressNearbyChecked:
                [self makeItemSuccessWithType:XPKeyCheckingCellTypeNearby];
                break;
            case XPKeyCheckProgressResetBleChecking:
                [self makeItemCheckingWithType:XPKeyCheckingCellTypeResetBle];
                break;
            case XPKeyCheckProgressResetBleChecked:
                [self makeItemSuccessWithType:XPKeyCheckingCellTypeResetBle];
                break;
            case XPKeyCheckProgressRestartChecking:
                [self makeItemCheckingWithType:XPKeyCheckingCellTypeRestart];
                break;
            case XPKeyCheckProgressRestartChecked:
                [self makeItemSuccessWithType:XPKeyCheckingCellTypeRestart];
                break;
            case XPKeyCheckProgressConnectChecking:
                [self makeItemCheckingWithType:XPKeyCheckingCellTypeConnect];
                break;
            case XPKeyCheckProgressConnectChecked:
                [self makeItemSuccessWithType:XPKeyCheckingCellTypeConnect];
                break;
            case XPKeyCheckProgressCommandChecking:
                if(self.command == XPTBoxCommandUnlock){
                    if(self.isStart){
                        [self makeItemCheckingWithType:XPKeyCheckingCellTypeStart];
                    }else{
                        [self makeItemCheckingWithType:XPKeyCheckingCellTypeUnlock];
                    }
                }else{
                    [self makeItemCheckingWithType:XPKeyCheckingCellTypeLock];
                }
                break;
            case XPKeyCheckProgressCommandChecked:
                if(self.command == XPTBoxCommandUnlock){
                    if(self.isStart){
                        [self makeItemSuccessWithType:XPKeyCheckingCellTypeStart];
                    }else{
                        [self makeItemSuccessWithType:XPKeyCheckingCellTypeUnlock];
                    }
                }else{
                    [self makeItemSuccessWithType:XPKeyCheckingCellTypeLock];
                }
                break;
            case XPKeyCheckProgressResetKeyChecking:
                [self makeItemCheckingWithType:XPKeyCheckingCellTypeResetKey];
                break;
            case XPKeyCheckProgressResetKeyChecked:
                [self makeItemSuccessWithType:XPKeyCheckingCellTypeResetKey];
                break;
            default:
                break;
        }
        self.checkingView.items = [NSArray arrayWithArray:self.items];
    } error:^(NSError * _Nullable error) {
        @strongify(self);
        [self updateView];

        if(error.code == XPKeyCheckErrorCodeCancel){
            [self.navigationController popViewControllerAnimated:YES];
            return;
        }

        if(error.code == XPKeyCheckErrorCodeGoToFinal){
            [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_FINAL module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];

            self.finalView.hidden = NO;
            self.failView.hidden = YES;
            self.checkingView.hidden = YES;
            self.successView.hidden = YES;
            return;
        }

        self.currentError = error;
        NSString *title = error.userInfo[@"title"];
        if(title.length == 0){
            if(self.command == XPTBoxCommandUnlock){
                if(self.isStart){
                    title = @"启动失败";
                }else{
                    title = @"解锁失败";
                }
            }else{
                title = @"闭锁失败";
            }
        }
        self.failView.titleLabel.text = title;
        self.failView.subtitleLabel.text = error.localizedFailureReason;

        NSString *nextButtonTitle = @"重试";
        switch (error.code) {
            case XPKeyCheckErrorCodePoweredOff:
                nextButtonTitle = @"开启蓝牙";
                break;
            case XPKeyCheckErrorCodeNoPermission:
                nextButtonTitle = @"开启权限";
                break;
            case XPKeyCheckErrorCodeFailToExecute:
                nextButtonTitle = @"重新检查";
                break;
            default:
                break;
        }
        [self.failView.nextButton setTitle:nextButtonTitle forState:UIControlStateNormal];

        self.failView.hidden = NO;
        self.finalView.hidden = YES;
        self.checkingView.hidden = YES;
        self.successView.hidden = YES;
    } completed:^{
        @strongify(self);
        if(!(self.command == XPTBoxCommandUnlock && self.from == 1 && self.isRemoteComplete)){
            if(self.command == XPTBoxCommandUnlock){
                if(self.isStart){
                    [XPToast showMessage:@"车辆已启动"];
                }else{
                    [XPToast showMessage:@"车门已解锁"];
                }
            }else if(self.command == XPTBoxCommandLock){
                [XPToast showMessage:@"车门已上锁"];
            }else{
                [XPToast showMessage:@"操作成功"];
            }
            [self.navigationController popToRootViewControllerAnimated:YES];
        }

        [self updateView];
        self.successView.command = self.command;
        self.successView.isStart = self.isStart;
        self.successView.hidden = NO;
        self.checkingView.hidden = YES;
        self.failView.hidden = YES;
        self.finalView.hidden = YES;
    }];
}

