- (NSString *)refreshTokenHelperRefreshPath {
    return APIUrlRefreshToken;
}

- (BOOL)refreshTokenHelperShouldUpdateRefreshToken {
    // 如果token都没有了，则不需要进行刷新的尝试了
    if([CTMediator loginInfoViewModel].loginInfo.refreshToken.length <= 0 || [CTMediator loginInfoViewModel].loginInfo.accessToken.length <= 0) {
        return NO;
    }
    return YES;
}
- (void)refreshTokenHelperDidRespondWithData:(id)data {
    LoginInfo *loginInfo = [LoginInfo yy_modelWithJSON:data];
    [[CTMediator loginInfoViewModel] updateLoginInfo:loginInfo];
}
- (void)refreshTokenHelperDidRespondErrorWithCode:(NSInteger)code message:(NSString *)message {
    [XPStatisticsMgr sendEvent:XP_APM_EVENT_REFRESH_ACCESS_TOKEN_ERROR module:XP_APM_MODULE data:@{@"error-code" : @(code), @"error-message" : message ? : @"fail" }];
}
- (void)refreshTokenHelperDidUpdate {
    //延迟0.2秒是为了保证能取得最新的token,因为保存token需要时间
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.2 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        [[NSNotificationCenter defaultCenter] postNotificationName:RefreshAccessTokenSuccessNotificaiton object:nil];
    });
}


#pragma mark -
#pragma mark - ResponseHandlerDelegate

- (void)responseHandlerDidHandleRefreshTokenInvalidWithMessage:(NSString * _Nullable)message {
    DLogTagInfo(kBLEKeyTag, @"登录态过期，断开蓝牙");
    [XPBLEHandlerManager disconnectIsForce:true];
    [XPBLEKeyManager.instance deleteSafeKey];

    UIViewController *currentFrontVC = [UIViewController currentFrontViewController];
    if (currentFrontVC && [currentFrontVC isKindOfClass:[XPSplashViewController class]]) {
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(2 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
            //广告页消失后，再显示登出消息
            if (CTMediator.isLogin) {
                //如果此时还处于登录状态，才显示登出消息
                [self responseHandlerDidHandleRefreshTokenInvalidWithMessage:message];
            }
        });
        return;
    }
    xp_async_execute_in_main_thread(^{ [XPToast dismissLoadingMessage]; });
    [CTMediator clearAllLoginInfos];

    if (self.isShowingLogoutAlertController) {
        //如果已经在显示登出弹框，包括外部弹框，则不再显示此弹框
        DLogTagInfo(@"XPCoreSessionAppLaunch", @"已经在显示登出弹框，包括外部弹框，则不再显示此登出弹框");
        return;
    }
    self.isShowingLogoutAlertController = YES;

    if (!message || 0 == message.length) {
        message = XP_ACCOUNT_LOCALIZED_STRING(@"account_server_error_message", nil);
    }
    @weakify(self);
    XPUIAlertController *alertVC = [XPUIAlertController alertControllerWithTitle:message message:nil imageURLString:nil localImage:nil configuration:^(XPUIAlertControllerConfig * _Nonnull config) {
        config.titleLabel.font = kPingFangSCMediumFont(18);
        config.messageTextView.textAlignment = NSTextAlignmentLeft;
    }];

    XPUIAlertAction *confirmAction = [XPUIAlertAction actionWithTitle:XP_ACCOUNT_LOCALIZED_STRING(@"account_force_logout_cancel_button_title", nil)
                                                            style:UIAlertActionStyleDefault
                                                    actionHandler:^(XPUIAlertAction * _Nonnull action) {
        @strongify(self);
        [CTMediator jumpToLoginWithCompletion:^() { DLogInfo(@"登录%@",@"成功"); } cancelAction:^{ DLogInfo(@"登录%@",@"失败"); }];
        self.isShowingLogoutAlertController = NO;
    } configuration:nil];
    [alertVC addAction:confirmAction];
    [[UIViewController currentFrontViewController] presentViewController:alertVC animated:YES completion:nil];
}

- (void)responseHandlerDidHandleTeeDecryptFailedWithMessage:(NSString * _Nullable)message{
    [KeyChain save:kXPBizTeeShouldIgnoreInitKey data:@NO];
    [[XPTeeSecurityManager instance] loadIndiv:^(NSError * _Nonnull error, BOOL didInit, CGFloat duration) { } didInit:^{ }];
}

- (void)responseHandlerDidHandleFailedWithMessage:(NSString * _Nullable)message {
    if (message.length > 0) {
        [XPToast showMessage:message];
    } else {
        [XPToast showMessage:XP_COMMON_MODULE_LOCALIZED_STRING(@"http_response_common_message", nil)];
    }
}

