    if(XPCoreSessionAppLaunch.sharedInstance.encryptionType == HttpRequestEncryptionTypeTee) {
        sucess = [XPTeeSecurityManager instance].isIndivSaveSuccess;
    }
    return sucess;
}
- (BOOL)isNeedDencryptedInResponse {
    return XPCoreSessionAppLaunch.sharedInstance.encryptionType != HttpRequestEncryptionTypeNone;
}
- (NSDictionary * _Nullable)dencryptedDictionaryInResponseWithString:(NSString * _Nonnull)string {
    NSDictionary *dataDic = nil;
    if(XPCoreSessionAppLaunch.sharedInstance.encryptionType == HttpRequestEncryptionTypeTee) {
        dataDic = [[[XPTeeSecurityManager instance] decode4Network:string] toDictionary];
    }
    return dataDic;
}


