1055	- (void)endBackgroundTask {
1056	    DLogTagInfo( kBackgroundTaskTag, @"后台任务时间结束，所有线程即将被挂起");
1057	    [XPCarSDK notifyAppWillSuspend];
1058	    [[XPMatrixHandler shareInstance] notifyAppWillSuspend];
1059	    if ([NSThread isMainThread]) {
1060	        [self.backgroundTaskTimer invalidate];// 停止定时器
1061	        /*  每个对 beginBackgroundTaskWithExpirationHandler:方法的调用,必须要相应的调用 endBackgroundTask:方法。这样，来告诉应用程序你已经执行完成了。
1062	         也就是说,我们向 iOS 要更多时间来完成一个任务,那么我们必须告诉 iOS 你什么时候能完成那个任务。
1063	         标记指定的后台任务完成
1064	         */
1065	        if (self.backgroundTaskIdentifier != UIBackgroundTaskInvalid) {
1066	            [[UIApplication sharedApplication] endBackgroundTask:self.backgroundTaskIdentifier];
1067	            // 销毁后台任务标识符
1068	            self.backgroundTaskIdentifier = UIBackgroundTaskInvalid;
1069	        }
1070	
1071	    } else {
1072	        dispatch_sync(dispatch_get_main_queue(), ^(void) {
1073	            [self.backgroundTaskTimer invalidate];// 停止定时器
1074	            /*  每个对 beginBackgroundTaskWithExpirationHandler:方法的调用,必须要相应的调用 endBackgroundTask:方法。这样，来告诉应用程序你已经执行完成了。
1075	             也就是说,我们向 iOS 要更多时间来完成一个任务,那么我们必须告诉 iOS 你什么时候能完成那个任务。
1076	             标记指定的后台任务完成
1077	             */
1078	            if (self.backgroundTaskIdentifier != UIBackgroundTaskInvalid) {
1079	                [[UIApplication sharedApplication] endBackgroundTask:self.backgroundTaskIdentifier];
1080	                // 销毁后台任务标识符
1081	                self.backgroundTaskIdentifier = UIBackgroundTaskInvalid;
1082	            }
1083	        });
1084	    }
1085	}
