1206	- (void)registerAPNS:(BOOL)isFirstInstall {
1207	    if ([[[UIDevice currentDevice] systemVersion] floatValue] < 10.0) {
1208	        [[UIApplication sharedApplication] registerUserNotificationSettings:
1209	         [UIUserNotificationSettings settingsForTypes:
1210	          (UIUserNotificationTypeSound | UIUserNotificationTypeAlert | UIUserNotificationTypeBadge)
1211	                                           categories:nil]];
1212	        [[UIApplication sharedApplication] registerForRemoteNotifications];
1213	    } else {
1214	        
1215	        UNUserNotificationCenter *center = [UNUserNotificationCenter currentNotificationCenter];
1216	        center.delegate = self;
1217	        [center requestAuthorizationWithOptions:UNAuthorizationOptionAlert | UNAuthorizationOptionBadge | UNAuthorizationOptionSound completionHandler:^(BOOL granted, NSError * _Nullable error) {
1218	            static NSString* kLastShowSystemNotificationAlertDate = @"kLastShowSystemNotificationAlertDate";
1219	            if (isFirstInstall) {
1220	                NSTimeInterval timestamp = [[NSDate date] timeIntervalSince1970];
1221	                [KeyValueStore saveNumber:@(timestamp) withObjectId:kLastShowSystemNotificationAlertDate userId:nil];
1222	            }
1223	            // 无论是否授权都需要注册
1224	            [[UIApplication sharedApplication] registerForRemoteNotifications];
1225	            if (granted) {
1226	                // granted
1227	                DLogTagInfo( kSystemPushTag, @"User authored notification.");
1228	                dispatch_async(dispatch_get_main_queue(), ^{
1229	                    [MessageCenterModel.shareInstance.pushNotifyDialogDismissSignal sendCompleted];
1230	                });
1231	            } else {
1232	                // not granted
1233	                DLogTagInfo( kSystemPushTag, @"User denied notification.");
1234	                [MessageCenterModel.shareInstance.pushNotifyDialogDismissSignal sendCompleted];
1235	                if (!isFirstInstall) {
1236	                    NSDate* now = [NSDate date];
1237	                    NSNumber* number =  [KeyValueStore numberForObjectId:kLastShowSystemNotificationAlertDate userId:nil];
1238	                    NSDate* lastDate = [NSDate dateWithTimeIntervalSince1970:number.doubleValue];
1239	                    const uint64_t second = (uint64_t)[now timeIntervalSinceDate:lastDate];
1240	                    __CHECK(second > 3600 * 24);
1241	                    dispatch_async(dispatch_get_main_queue(), ^{
1242	                        [self checkRemoteNotificationsOpen:isFirstInstall];
1243	                    });
1244	                }
1245	            }
1246	        }];
1247	    }
1248	}
