1305	        if (self.isLaunchEventFinished) {
1306	            return;
1307	        }
1308	        self.isLaunchEventFinished = YES;
1309	        
1310	        NSInteger isLogin = 0;
1311	        if (scene == XPLaunchSceneLoginPageAppeared) {
1312	            isLogin = 1;
