1316	        NSInteger launchTimeOfMSeconds = round(launchTime * 1000);
1317	        
1318	        if (self.initTimeOfMSeconds == 0) {
1319	            self.initTimeOfMSeconds = launchTimeOfMSeconds;
1320	        }
1321	        
1322	        DLogTagInfo(@"AppLaunch", @"Launch Total Time: %@, Init:%@, OnlineAd: %@, VideoAd %@, isLogin %@, Current Tabbar index: %@, userType: %@", @(launchTimeOfMSeconds), @(self.initTimeOfMSeconds), @(self.onlineAdTimeOfMSeconds), @(self.videoAdTimeOfMSeconds), @(isLogin), @(CTMediator.tabBarController.selectedIndex), @(CTMediator.currentUserInfo.flag));
