1324	        [Bulk writeWithType:BULK_APM event:@"B063" module:@"P00001" data:@{
1325	            @"init": @(self.initTimeOfMSeconds),
1326	            @"ad": @(self.onlineAdTimeOfMSeconds),
1327	            @"video": @(self.videoAdTimeOfMSeconds),
1328	            @"duration": @(launchTimeOfMSeconds),
1329	            @"is_login": @(isLogin),
1330	            @"tab_name": isLogin ? @"" : ([XPTabBarCenter.instance selectedTabbarItemTitle] ?: @""),
1331	        }];
