@implementation XPLaunchTaskMgr

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

- (instancetype)init {
    if (self = [super init]) {
        _isOnSplashAd = NO;
        _isHomeAppeared = NO;
        _isHomeAppearedDelay = NO;
        _isLaunchHomeReady = NO;
        _isLaunchEventFinished = NO;
        [self startupBBox];
    }
    return self;
}


+ (XPLaunchTaskMgr *)instance {
    static XPLaunchTaskMgr *gXPLaunchTaskMgr = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        gXPLaunchTaskMgr = [[XPLaunchTaskMgr alloc] init];
    });
    return gXPLaunchTaskMgr;
}

- (void)setLaunchOptions:(NSDictionary *)launchOptions {
    _launchOptions = launchOptions;

    [XPApplicationState sharedApplication].applicationState = [UIApplication sharedApplication].applicationState;
    [BabyAppState sharedApplication].applicationState = [UIApplication sharedApplication].applicationState;
}

- (BOOL)startProtect {
    id obj = [CloudConfig configForKeyPath:@"safemodel.appstart.count"];
    if (NO == [obj isKindOfClass:NSNumber.class]) { return YES; }
    NSNumber *num = (NSNumber *)obj;
    if (num.integerValue <= 0) { return YES; }
    if (XPStartProtector.isCrashTooFast) { return YES; }

    NSInteger count = [NSUserDefaults.standardUserDefaults integerForKey:@XP_START_PROTECT_COUNT_KEY];
    count += 1;
    [NSUserDefaults.standardUserDefaults setInteger:count forKey:@XP_START_PROTECT_COUNT_KEY];
    if (count > num.integerValue) { return YES; }

    [XPStartProtector setEventReportHandler:^(NSDictionary * _Nonnull data) {
        if (data.count > 0) {
            [Bulk writeWithType:BULK_APM event:@"B056" module:@"P00004" data:data];
        }
    }];
    return [XPStartProtector start];
}

#pragma mark -
#pragma mark - Before UI

- (void)startupOnAppDidFinishLauchingBeforeUI {

    CFTimeInterval startTime = CACurrentMediaTime();

    //记录app开始使用的时间
    [self resetAppLaunch];

#if ENABLE_DOKIT
    [DoraemonManager.shareInstance addPluginWithTitle:@"RN调试" icon:@"dokit_react_native" desc:@"" pluginName:@"XPDKReactNativePlugin" atModule:@"业务工具" buriedPoint:@"dokit_app_rn_debug"];
    [DoraemonManager.shareInstance addPluginWithTitle:@"埋点信息" icon:@"dokit_uried_point" desc:@"" pluginName:@"XPDKStatisticsPlugin" atModule:@"业务工具" buriedPoint:@"dokit_app_bi"];
    [DoraemonManager.shareInstance addPluginWithTitle:@"二维码扫描" icon:@"doraemon_scan" desc:@"" pluginName:@"XPDKQRCodePlugin" atModule:@"业务工具" buriedPoint:@"dokit_app_scan_qrcode"];
    [DoraemonManager.shareInstance addPluginWithTitle:@"车控蓝牙" icon:@"doraemon_weaknet" desc:@"" pluginName:@"XPBLECppPlugin" atModule:@"业务工具" buriedPoint:@"blue_car_control"];
    [DoraemonManager.shareInstance addPluginWithTitle:@"调试工具" icon:@"doraemon_setting" desc:@"" pluginName:@"DebugPlugin" atModule:@"业务工具" buriedPoint:@"dokit_debug_tool"];
    [DoraemonManager.shareInstance addPluginWithTitle:@"路由跳转" icon:@"doraemon_location" desc:@"" pluginName:@"DKRouterPlugin" atModule:@"业务工具" buriedPoint:@"dokit_router_tool"];
    [DoraemonManager.shareInstance addPluginWithTitle:@"设备/用户信息" icon:@"doraemon_app_info" desc:@"" pluginName:@"DKInfoPlugin" atModule:@"业务工具" buriedPoint:@"dokit_info_tool"];

    [DoraemonManager.shareInstance install];

    BOOL isShow = YES;
    NSUserDefaults *userDefaults = [NSUserDefaults standardUserDefaults];
    NSNumber *showNum = [userDefaults objectForKey:@"kShowMonitorViewKey"];
    if (showNum) {
        isShow = [showNum boolValue];
    }
    if (isShow) {
        [DoraemonManager.shareInstance showDoraemon];
    } else {
        [DoraemonManager.shareInstance hiddenDoraemon];
    }
#endif

    [XPRuntimeSecurityChecker work];

    // 初始化路由，必须在初始化用户信息前，不然会找不到模块接口
    [RouterHelperExtension initFullRouter];

    /// 初始化 GIO
    [XPStatisticsMgr startupGrowingIOWithLaunchOptions:_launchOptions];

    /// 初始化用户信息
    [XPLaunchTaskMgr initModules];

    /// 启动埋点
    [XPStatisticsMgr sendEvent:XP_BASE_EVENT_APP_LAUNCH module:XP_BASE_MODULE];

    // 加密模块
    [XPCoreSecurityAppLaunch.sharedInstance run];
    // 网络模块
    [XPCoreSessionAppLaunch.sharedInstance run];
    // AppGroup
    [XPAppGroupAppLaunch.sharedInstance run];

    //初始化XLog
    [self startupXPLog];

    //CrashReportSDK: Sentry
    [XPLogFileHandle initCrashReportSDK];

    [[XPMatrixHandler shareInstance] installMatrix];

    NSString *buildType = @"Release";
#if DEBUG
    buildType = @"Debug";
#endif
    DLogTagInfo(@"AppLaunch", @"=====================App Start =====================\n appNameVersion:%@, appPhase:%@, buildType:%@, appBundleId:%@, appChannel:%@, deviceModelName:%@, deviceID:%@ SysAppState:%@ XPAppState:%@ BabyAppState:%@\n", [XPUtility appNameVersion], [XPUtility appPhase], buildType, [XPUtility appBundleId], [XPUtility appChannel], [XPUtility deviceModelName], [XPUtility deviceID], @([UIApplication sharedApplication].applicationState), @([XPApplicationState sharedApplication].applicationState), @([BabyAppState sharedApplication].applicationState));

    [XPSDWebImageTask execute];

    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
        DLogTagInfo(@"AppLaunch", @"startupOnAppDidFinishLauchingBeforeUI on thread");
        //初始化统计模块，统计模块初始话要尽早
        [[XPStatisticsMgr instance] setupStatistics];

        //注册页面路由跳转
        [XPRouterUtil registerAllResidentRouters];
        //创建一些必要的目录
        [XPFileUtil checkToCreateAppDirectory];

        //强制记录当前版本
        [XPAPPVersion force];
        [self reportTaskEvent:__PRETTY_FUNCTION__ startTime:startTime];
    });

    [ScreenshotDetector.shared startDetect];
}


#pragma mark -
#pragma mark - After UI

- (void)startupOnAppDidFinishLauchingAfterUI {
    DLogTagInfo(@"AppLaunch", @"=====================App Start LauchingAfterUI=====================");
    CFTimeInterval startTime = CACurrentMediaTime();

    //高德地图
    NSString* mapAppKey = AMapAppKey;
    [AMapServices sharedServices].apiKey = mapAppKey;

    //Sharetrace 获取安装携带的参数
    [[XPSharetraceManager shareInstance] getInstallTrace];

    //逆地图埋点上报
    [LocationHelper sharedInstance].regeocodeStatisticsBlock = ^{
        [XPLocationManager statisticsAMapUsageWithSceneName:@"regeocode_location_helper"];
    };

    // 监听配置获取成功的通知
    @weakify(self);
    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
        @strongify(self);
        DLogTagInfo(@"AppLaunch", @"startupOnAppDidFinishLauchingAfterUI on thread");
        // 初始化 CloudConfig
        [self startupCloudConfig];

        // 点击通知拉起app，设置本地通知delegate，否则非注册在前台无法调用对应willpresent推通知方法
        if (![CTMediator isLogin]) {
            UNUserNotificationCenter *center = [UNUserNotificationCenter currentNotificationCenter];
            center.delegate = self;
        }

    #ifdef DEBUG
        [[TestManager sharedManager] intercepter];
    #endif
        [[XPPageEventManager instance] intercepter];

        [[[NSNotificationCenter defaultCenter] rac_addObserverForName:LocationUpdatedNotification object:nil] subscribeNext:^(NSNotification * _Nullable x) {
            CLLocation *location = [x.object objectForKey:@"location"];
            BOOL shouldReport = [KeyValueStore BOOLForObjectId:kAccountIntentionShouldReportKey userId:@(CTMediator.uid).stringValue];
            if (location) {
                DLogTagInfo(kUseLocationTag, @"request %@",location ?: @"");
                [XPStatisticsMgr updateGrowingIOLocation:location];
                if (shouldReport) {
                    [XPAccountIntentionCollectionViewModel requestRegisterReportWithLocation:location];
                }
            }

        }];

        // 抖音和bilibili同级，随便一个生效即可
        if ([[XPDouYinAdTransferReportManager sharedManager] shouldReport] || [[XPBilibiliAdTransferReportManager sharedManager] shouldReport]) {
            [XPLocationManager statisticsAMapUsageWithSceneName:@"ad_report"];
            [XPLocationUtils requestLocationWithCompletion:^(XPLocationCacheType cacheType, CLLocation * _Nullable location, AMapLocationReGeocode * _Nullable regeocode, NSError * _Nullable error) {
                //抖音
                [[XPDouYinAdTransferReportManager sharedManager] reportAppRegisterWithLng:location.coordinate.longitude lat:location.coordinate.latitude];
                [[XPDouYinAdTransferReportManager sharedManager] saveShouldReport:NO];
                //bilibili
                [[XPBilibiliAdTransferReportManager sharedManager] reportAppRegisterWithLng:location.coordinate.longitude lat:location.coordinate.latitude];
                [[XPBilibiliAdTransferReportManager sharedManager] saveShouldReport:NO];
            }];
        }

        //初始化用户协议管理模块
        [CTMediator initProtocolManager];
        [self reportTaskEvent:__PRETTY_FUNCTION__ startTime:startTime];
    });
}



#pragma mark -
#pragma mark - Delay Triger

- (void)startupOnAppDidFinishLauchingDelayTriger {
