- (void)startupOnAppWillEnterForeground {
    DLogTagInfo(@"AppLaunch", @"=====================App Will EnterForeground=====================");
    CFTimeInterval startTime = CACurrentMediaTime();

    //重置app开始使用的时间
    [self resetAppLaunch];

    //初始化Tee加密
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(1.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        [self startupOnInitSecurity:nil];
    });

    @weakify(self);
    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
        @strongify(self);
        DLogTagInfo(@"AppLaunch", @"startupOnAppWillEnterForeground on thread");
        //每次从后台回来都刷新userInfo，防止登录被挤下线后mqtt收不到消息导致跳不到登录页
        [self refreshUserInfo];
        [MessageNotifcationHandler updateCategories];
    });

    //如果后台剩余时间小于10s，则表明mqtt已断开，需要重连
    DLogTagInfo( kBackgroundTaskTag, @"剩余时间：%f", self.backgroundTimeRemaining);

    if((self.backgroundTimeRemaining < backgroundDisconnectMQTTRemainingTime || ![MQTTPublisher sharedManager].isConnected)
       && ([CTMediator isLogin]) ) {
        //通知首页下拉刷新
        [[NSNotificationCenter defaultCenter] postNotificationName:RefreshCarOwnerHomeDataNotificaiton object:nil];
    }
    //防止endBackgroundTask被重复调用
    [self endBackgroundTaskIfNeed];

    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(1.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        // 检查更新
        [XPUpgradeAppManager checkUpgrade];
    });

    //车图模块记录唤醒
    [[XPUnityLifeCircleManager sharedInstance] willEnterForgroundAction];

    //从后台返回前台时，检查网络状态，适时启动udp监听，用于接收大屏发送过来的文件
    XPVehicleFileTransferManager *manager = [XPVehicleExt createVehicleTransferFileManager];
    manager.enabled = YES;
    [manager checkConnection];

    BOOL isLoginScenePolicyAgreed = [XPUserProtocolManager isLoginScenePolicyAgreed];
    if (isLoginScenePolicyAgreed) {
        // 临时注释代码，解决某些机器返回前台反复弹广告问题。预计4.21.0修改数据库彻底修复此问题，再取消此注释。
//        [[XPActivityManager sharedManager] queryAndShowOperationActivity];
        [[MessageCenterModel shareInstance] refreshUnreadMessageCount];
    }

    [SystemConfig updateSystemConfigWithForce:YES];
    [XPExtensionHelper setupIfNeed];

    [self reportTaskEvent:__PRETTY_FUNCTION__ startTime:startTime];
}

- (void)startupOnAppWillResignActive {
    DLogTagInfo(@"AppLaunch", @"=====================App Will ResignActive=====================");
    CFTimeInterval startTime = CACurrentMediaTime();

    [[NSNotificationCenter defaultCenter] postNotificationName:SaveRecordVideoWhenEnterBackgroundNotification object:nil];
    [self reportTaskEvent:__PRETTY_FUNCTION__ startTime:startTime];
}

- (void)startupOnAppDidEnterBackground {
    DLogTagInfo(@"AppLaunch", @"=====================App Did EnterBackground=====================");

    // 标记一个长时间运行的后台任务将开始
    // 通过调试，发现，iOS给了我们额外的3分钟（180s）来执行这个任务。
    if (self.backgroundTaskIdentifier == UIBackgroundTaskInvalid) {
        @weakify(self);
        self.backgroundTaskIdentifier = [[UIApplication sharedApplication] beginBackgroundTaskWithExpirationHandler:^(void) {
            @strongify(self);
            // 当应用程序留给后台的时间快要到结束时（应用程序留给后台执行的时间是有限的），这个Block块将被执行
            [self endBackgroundTask];
        }];
    }

    // 模拟一个Long-Running Task
    [self.backgroundTaskTimer invalidate];
    _backgroundTaskTimer = [NSTimer scheduledTimerWithTimeInterval:1.0f
                                                            target:self
                                                          selector:@selector(timerMethod:)
                                                          userInfo:nil
                                                           repeats:YES];
    self.backgroundTimeRemaining = [[UIApplication sharedApplication] backgroundTimeRemaining];
}

- (void)startupOnAppWillTerminate {
    DLogTagInfo(@"AppLaunch", @"=====================App Will Terminate=====================");

    //断开mqtt
    if (MQTTPublisher.sharedManager.isConnected) {
        [[MQTTPublisher sharedManager] disconnectServer];
    }
    if([XPBLEKeyManager.instance isSafeKeyOrCertKeyExisted]) {
        DLogTagInfo(@"AppLaunch", @"存在有效钥匙，app被即将kill时断开蓝牙");
        if (CTMediator.isE28 || ![[XPMultiBleManager sharedManager] getIsDriverMode]) {
            [XPBLEHandlerManager disconnectIsForce:YES];
        } else {
            [XPBLEHandlerManager disconnectIsForce:NO];
        }
    }
    [XPLog stop];

    // 强杀app时间记录
    uint64_t currentTime = [XPUtility dateTimestamp];
    [[NSUserDefaults standardUserDefaults] setDouble:(double)currentTime forKey:@"appTerminateTime"];
    [[NSUserDefaults standardUserDefaults] synchronize];
}


