+ (void)setupXPLogInfo {
    NSString *VIN = CTMediator.vin;
    NSInteger uid = CTMediator.uid;
    if (VIN.length == 0 && uid != 0) {
        VIN = [KeyValueStore stringForObjectId:@"com.xiaopeng.defaultCarVinLocal" userId:[NSString stringWithFormat:@"%ld", uid]];
    }

