#import <Foundation/Foundation.h>
#import <ReactiveObjC/ReactiveObjC.h>
#import "XPBLEDefined.h"
#import "XPBLEHandler.h"
#import "XPBleCanSignalValueDefined.h"
@class XPBLEHandlerManager;

NS_ASSUME_NONNULL_BEGIN

@interface XPBLEHandlerManager : NSObject

@property (nonatomic, assign) XPBLESystemState bleSystemState;

@property (nonatomic,strong,readonly) RACSubject* sendBleConnectStateSingal;

@property (nonatomic, assign) BOOL hasLoginLaunch;

+ (instancetype)manager;

+ (void)readBluetoothRSSI;

+ (void)disconnectIsForce:(BOOL)isForce;

+ (void)resetBlueScanStyle;

- (void)start;

- (void)switchCar:(NSString *)vin isInControlPage:(BOOL)isInControlPage;

- (void)userLoginOutEvent;

- (void)deleteMyBleKeyEvent;

- (void)startBleConnectAndAuthComplete:(ConnectAndAuthBlock)complete;

- (NSString *)getBleHandlerEcuNameByDeviceUUID:(NSString *)deviceUUID;

- (XPBLEHanderConnectState)getCommuicateBLEConnectState;
- (XPBLEHanderConnectState)getBleHandlerConnectState:(NSString *)ecuName;

- (BOOL)isCommunicateHandler:(NSString *)ecuName;

- (BOOL)commuicateBleIsSendingBleCommand;

- (int32_t)getCommunicateRssi;

- (void)openPollingRssiCollectChannel;

- (void)closePollingRssiCollectChannel;

// 清理车辆蓝牙连接缓存信息，下次连接将重走扫描
- (void)resetConnectInfos;

- (BOOL)peripheralIsNil;

- (void)resetBleConnectCount;

//发送指令
- (void)sendCDCULoginVerifyMessage:(NSDictionary *)input complete:(void (^)(NSError * _Nullable error))complete;

- (void)sendRkeControlIFFAMessage:(NSDictionary *)input complete:(void (^)(NSError * _Nullable error))complete;

- (void)sendRkeControlCertMessage:(NSDictionary *)input complete:(void (^)(NSError * _Nullable error))complete;

- (void)sendBleParkingRequestMessage:(NSDictionary *)input complete:(void (^)(NSError * _Nullable))complete;

- (void)sendBleParkingHeartMessage:(NSDictionary *)input complete:(void (^)(NSError * _Nullable))complete;

- (void)sendBleInfoMessage:(NSDictionary *)input complete:(void (^)(NSError * _Nullable))complete;

- (void)sendSyncBleHeartMessage:(NSDictionary *)input ecuName:(NSString *)ecuName complete:(void (^)(NSError * _Nullable))complete;

- (void)sendSelfCalibrationMessage:(NSDictionary *)input complete:(nullable void (^)(NSError *error,NSDictionary *rssiValue))complete;

- (void)sendRssiCollectMessage:(NSDictionary *)input complete:(nullable void (^)(NSError *error))complete;

- (void)sendPollingCustomerDataMessage:(NSDictionary *)input complete:(nullable void (^)(NSError *error))complete;

- (void)sendLeaveParkMessage:(NSDictionary *)message complete:(void (^)(NSError * _Nullable error))complete;

- (void)sendLeaveParkMessage:(NSDictionary *)message complete:(void (^)(NSError * _Nullable error))complete;

- (void)synchronizeMainBLEConnectState;

@end

NS_ASSUME_NONNULL_END

//
//  XPVehicleSDK+DigitalKey.swift
//  XPVehicleSDK
//
//  Created by xpeng on 2024/8/21.
//

import Foundation

extension XPVehicleSDK {
    ///  当前车 钥匙管理
    /// - Returns: DigitalKeyManagerProtocol
    public static func digitalKeyManager() -> DigitalKeyManagerProtocol? {
        return XPVehicleSDK.currentVehicle()?.digitalKeyManager
    }

    ///  获取当前车钥匙
    /// - Parameter keyCardType: KeyCardType
    /// - Returns: DigitalKey
    public static func digitalKey(keyCardType: KeyCardType) -> DigitalKey? {
        return XPVehicleSDK.digitalKeyManager()?.digitalKey(keyCardType: keyCardType)
    }

    ///  获取当前车钥匙列表
    /// - Parameter keyCardType: KeyCardType
    /// - Returns: Array
    public static func digitalKeyList(keyCardType: KeyCardType) -> Array<Any>? {
        return XPVehicleSDK.digitalKeyManager()?.digitalKeyList(keyCardType: keyCardType)
    }

    /// 是否存在可用的蓝牙钥匙
    /// - Returns: bool
    public static func existValidKey() -> Bool {
        return XPVehicleSDK.digitalKeyManager()?.existValidBleKey() ?? false
    }

    ///  是否存在待激活的数字钥匙
    /// - Returns: bool
    public static func existToBeActivateBLEKey() -> Bool {
        return XPVehicleSDK.digitalKeyManager()?.existToBeActivateBLEKey() ?? false
    }

    /// 获取可用钥匙
    /// - Returns: DigitalKey
    public static func validBleKey() -> DigitalKey? {
        return XPVehicleSDK.digitalKeyManager()?.validBlePrivateKey()
    }

    /// 设置所以指令是否免生物识别验证，默认否（用户在弹窗设置后本地缓存）
    /// - Parameter noBioVerfy: 是否
    /// - Returns: 无
    public static func configNoBioVerfy(noBioVerfy: Bool) {
        XPVehicleSDK.digitalKeyManager()?.configNoBioVerfy(noBioVerfy: noBioVerfy)
    }
}

