//  XPVehicleSDK
//
//  Created by Xpeng on 2025/5/7.
//

import Foundation
@objc(XPDigitalKeyStaticHandler)
open class DigitalKeyStaticHandler: NSObject {
    //当车辆被解除授权时，在刷新车列表之前预先清理钥匙数据
    @objc public static func clearCacheWhenAuthorizationCanceled(uid: UInt64, vin: String) {
        let digitalKeyList: [DigitalKey] = DigitalKey.queryDigitalKeyList(vin: vin)
        for key in digitalKeyList {
            if key.keyCardType == KeyCardType.MONA_BLE {
                CarService.deleteLocalBleKey(uid: uid, vin: vin)
            } else {
                key.removeAllKeyMessages()
            }
        }
        DigitalKey.removeAllKeys(vin: vin)
    }
}

