- (void)deleteSafeKey {
    DLogTagInfo(kBLEKeyTag, @"删除安全钥匙，并清理报文");

    XPBLEKeyCard * card = XPBLEKeyManager.instance.defaultCard;

    card.isRegisterInThisInstall = NO;
    card.status = XPBLEKeyCardStatusInvalid;

    if (![CTMediator isSDK2ndCar]) {
        [XPBLEKeyCard saveCards:@[card]];
    }

    dispatch_async(dispatch_get_global_queue(0, 0), ^{
        [self clearSafeKeyAuthData];
    });
}



@end

