- (BOOL)isSafeKeyOrCertKeyExistedInner2nd {
    if ([CTMediator isMona]) {
        if ([XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager existValidBlePrivateKey]) {
            return YES;
        }
        NSString *keyWithVin = [NSString stringWithFormat:@"com.xiaopeng.XPCreateMonaKeyViewController.waitNearCar.%@.%lld", XPVehicleSDK.shared.vehicleManager.currentVehicle.vehiclePreference.vin,[CTMediator uid]];
        if ([MMKV.defaultMMKV getBoolForKey:keyWithVin] && [XPVehicleSDK existToBeActivateBLEKey]) {
            return YES;
        }
        return NO;
    } else {
        return [XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager existValidBlePrivateKey];
    }
}

- (BOOL)isSafeKeyExisted {
    if ([CTMediator isSDK2ndCar]) {
        return [self isSafeKeyExistedInner2nd];
    }
    BOOL isExisted = (XPBLEKeyManager.instance.defaultCard && [XPBLEKeyManager.instance.defaultCard isValid]);
    if(isExisted) {
        DLogTagInfo(kBLEKeyTag, @"用户(uid:%@, vin:%@)存在安全钥匙", @([XPLoginSDKBridge sharedInstance].loginHandle.uid).stringValue, CTMediator.vin);
    } else {
        DLogTagInfo(kBLEKeyTag, @"用户(uid:%@, vin:%@)不存在安全钥匙", @([XPLoginSDKBridge sharedInstance].loginHandle.uid).stringValue, CTMediator.vin);
    }

