            CLLocation *location = [x.object objectForKey:@"location"];
            BOOL shouldReport = [KeyValueStore BOOLForObjectId:kAccountIntentionShouldReportKey userId:@(CTMediator.uid).stringValue];
            if (location) {
                DLogTagInfo(kUseLocationTag, @"request %@",location ?: @"");
