- (void)startupOnTasksBeforeSplash:(void(^)(NSError * error))complete {
    DLogTagInfo(@"AppLaunch", @"===================== startupOnTasksBeforeSplash =====================");
    CFTimeInterval startTime = CACurrentMediaTime();

    //云信IM 平台推送处理
    [[XPIMKitManager sharedManager] didReceiveLaunchOptions:self.launchOptions];

    if (EncryptionOpen) {
        [self startupOnInitSecurity:^(NSError *error) {
            if (error != nil) { return; }
            [self startupOnAfterInitSecurity:complete];
        }];
    } else {
        [self startupOnAfterInitSecurity:complete];
    }
    [self reportTaskEvent:__PRETTY_FUNCTION__ startTime:startTime];
}

