//注册APNS推送,必须在application:didFinishLaunchingWithOptions返回前调用
- (void)registerAPNS:(BOOL)isFirstInstall {
    if ([[[UIDevice currentDevice] systemVersion] floatValue] < 10.0) {
        [[UIApplication sharedApplication] registerUserNotificationSettings:
         [UIUserNotificationSettings settingsForTypes:
          (UIUserNotificationTypeSound | UIUserNotificationTypeAlert | UIUserNotificationTypeBadge)
                                           categories:nil]];
        [[UIApplication sharedApplication] registerForRemoteNotifications];
    } else {

        UNUserNotificationCenter *center = [UNUserNotificationCenter currentNotificationCenter];
        center.delegate = self;
        [center requestAuthorizationWithOptions:UNAuthorizationOptionAlert | UNAuthorizationOptionBadge | UNAuthorizationOptionSound completionHandler:^(BOOL granted, NSError * _Nullable error) {
            static NSString* kLastShowSystemNotificationAlertDate = @"kLastShowSystemNotificationAlertDate";
            if (isFirstInstall) {
                NSTimeInterval timestamp = [[NSDate date] timeIntervalSince1970];
                [KeyValueStore saveNumber:@(timestamp) withObjectId:kLastShowSystemNotificationAlertDate userId:nil];
            }
            // 无论是否授权都需要注册
            [[UIApplication sharedApplication] registerForRemoteNotifications];
            if (granted) {
                // granted
                DLogTagInfo( kSystemPushTag, @"User authored notification.");
                dispatch_async(dispatch_get_main_queue(), ^{
                    [MessageCenterModel.shareInstance.pushNotifyDialogDismissSignal sendCompleted];
                });
            } else {
                // not granted
                DLogTagInfo( kSystemPushTag, @"User denied notification.");
                [MessageCenterModel.shareInstance.pushNotifyDialogDismissSignal sendCompleted];
                if (!isFirstInstall) {
                    NSDate* now = [NSDate date];
                    NSNumber* number =  [KeyValueStore numberForObjectId:kLastShowSystemNotificationAlertDate userId:nil];
                    NSDate* lastDate = [NSDate dateWithTimeIntervalSince1970:number.doubleValue];
                    const uint64_t second = (uint64_t)[now timeIntervalSinceDate:lastDate];
                    __CHECK(second > 3600 * 24);
                    dispatch_async(dispatch_get_main_queue(), ^{
                        [self checkRemoteNotificationsOpen:isFirstInstall];
                    });
                }
            }
        }];
    }
}

- (BOOL)checkRemoteNotificationsOpen:(BOOL)isFirstInstall {
    __CHECK_RET([NSThread isMainThread], NO)
    __CHECK_RET(!isFirstInstall,NO);
    const BOOL isRegisteredForRemoteNotifications = [[UIApplication sharedApplication] isRegisteredForRemoteNotifications];
    __CHECK_RET(!isRegisteredForRemoteNotifications, NO);
    static NSString* kIsShowRemoteNotificationsCloseAlert = @"IsShowRemoteNotificationsCloseAlert";
    BOOL isShow = [KeyValueStore BOOLForObjectId:kIsShowRemoteNotificationsCloseAlert userId:nil];
    __CHECK_RET(!isShow, NO);
    __CHECK_RET(!CTMediator.isCurrentUserCarOwner, NO);
    [KeyValueStore saveBOOL:YES withObjectId:kIsShowRemoteNotificationsCloseAlert userId:nil];
    XPAlertController *alertVC = [XPAlertController alertControllerWithTitle:@"开启推送通知"
                                                                     message:@"打开通知，可以及时获知来自车辆的消息"
                                                              imageURLString:nil
                                                                  localImage:nil
                                                               configuration:^(XPAlertControllerConfig * _Nonnull config) {
                                                                   config.titleLabel.font = kPingFangSCMediumFont(18);
                                                                   config.messageTextView.textAlignment = NSTextAlignmentLeft;
                                                               }];
    XPAlertAction *cancelAction = [XPAlertAction actionWithTitle:@"取消"
                                                           style:UIAlertActionStyleCancel
                                                   actionHandler:nil configuration:nil];
    [alertVC addAction:cancelAction];

    XPAlertAction *confirmAction = [XPAlertAction actionWithTitle:@"去开启"
                                                            style:UIAlertActionStyleDefault
                                                    actionHandler:^(XPAlertAction * _Nonnull action) {
        NSURL *url = [NSURL URLWithString:UIApplicationOpenSettingsURLString];
        [[UIApplication sharedApplication] openURL:url options:@{} completionHandler:nil];
    } configuration:nil];
    [alertVC addAction:confirmAction];
    [[UIViewController currentFrontViewController] presentViewController:alertVC animated:YES completion:nil];
    return YES;
}

#pragma mark - 统计 statics
- (void)resetAppLaunch {
    self.startAppDate = [NSDate date];
    self.lastSceneDate = nil;
    self.initTimeOfMSeconds = 0;
    self.onlineAdTimeOfMSeconds = 0;
    self.videoAdTimeOfMSeconds = 0;
}

- (void)sendAppLaunchEventWithScene:(XPLaunchScene)scene {
    if (scene == XPLaunchSceneInitFinished) {
        self.initTimeOfMSeconds = round([[NSDate date] timeIntervalSinceDate:self.startAppDate] * 1000);
    } else if (scene == XPLaunchSceneVideoAdFinished) {
        if (self.lastSceneDate) {
            self.videoAdTimeOfMSeconds = round([[NSDate date] timeIntervalSinceDate:self.lastSceneDate] * 1000);
        }
    } else if (scene == XPLaunchSceneOnlineAdFinished) {
        if (self.lastSceneDate) {
            self.onlineAdTimeOfMSeconds = round([[NSDate date] timeIntervalSinceDate:self.lastSceneDate] * 1000);
        }
    } else if (scene == XPLaunchSceneLoginPageAppeared || scene == XPLaunchSceneHomeAppeared) {
        if (self.isLaunchEventFinished) {
            return;
        }
        self.isLaunchEventFinished = YES;

        NSInteger isLogin = 0;
        if (scene == XPLaunchSceneLoginPageAppeared) {
            isLogin = 1;
        }

        NSTimeInterval launchTime = [[NSDate date] timeIntervalSinceDate:self.startAppDate];
        NSInteger launchTimeOfMSeconds = round(launchTime * 1000);

        if (self.initTimeOfMSeconds == 0) {
            self.initTimeOfMSeconds = launchTimeOfMSeconds;
        }

        DLogTagInfo(@"AppLaunch", @"Launch Total Time: %@, Init:%@, OnlineAd: %@, VideoAd %@, isLogin %@, Current Tabbar index: %@, userType: %@", @(launchTimeOfMSeconds), @(self.initTimeOfMSeconds), @(self.onlineAdTimeOfMSeconds), @(self.videoAdTimeOfMSeconds), @(isLogin), @(CTMediator.tabBarController.selectedIndex), @(CTMediator.currentUserInfo.flag));

        [Bulk writeWithType:BULK_APM event:@"B063" module:@"P00001" data:@{
            @"init": @(self.initTimeOfMSeconds),
            @"ad": @(self.onlineAdTimeOfMSeconds),
            @"video": @(self.videoAdTimeOfMSeconds),
            @"duration": @(launchTimeOfMSeconds),
            @"is_login": @(isLogin),
            @"tab_name": isLogin ? @"" : ([XPTabBarCenter.instance selectedTabbarItemTitle] ?: @""),
        }];
    }

    self.lastSceneDate = [NSDate date];
}

- (void)reportTaskEvent:(const char *)task startTime:(CFTimeInterval)startTime {

    [Bulk writeWithType:BULK_APM event:@"B037" module:@"P00004" data:@{
        @"task_name": [NSString stringWithUTF8String:task] ?: @"",
        @"duration": @((int)(((CACurrentMediaTime() - startTime)) * 1000)),
        @"process_name": @"0",
        @"thread_name": NSThread.currentThread.name ?: @"",
    }];
}

