- (BOOL)startProtect {
    id obj = [CloudConfig configForKeyPath:@"safemodel.appstart.count"];
    if (NO == [obj isKindOfClass:NSNumber.class]) { return YES; }
    NSNumber *num = (NSNumber *)obj;
    if (num.integerValue <= 0) { return YES; }
    if (XPStartProtector.isCrashTooFast) { return YES; }

    NSInteger count = [NSUserDefaults.standardUserDefaults integerForKey:@XP_START_PROTECT_COUNT_KEY];
    count += 1;
    [NSUserDefaults.standardUserDefaults setInteger:count forKey:@XP_START_PROTECT_COUNT_KEY];
    if (count > num.integerValue) { return YES; }

    [XPStartProtector setEventReportHandler:^(NSDictionary * _Nonnull data) {
        if (data.count > 0) {
            [Bulk writeWithType:BULK_APM event:@"B056" module:@"P00004" data:data];
        }
    }];
    return [XPStartProtector start];
}

