// App处于前台时收到通知(iOS 10+)
- (void)userNotificationCenter:(UNUserNotificationCenter *)center willPresentNotification:(UNNotification *)notification withCompletionHandler:(void (^)(UNNotificationPresentationOptions options))completionHandler {
    if(notification.request.trigger && [notification.request.trigger isKindOfClass:[UNPushNotificationTrigger class]]) {//应用处于前台时的远程推送接受

        [MessageNotifcationHandler handlerRemoteNotification:notification];
        if ([CTMediator isLogin]) {
            if ([UIViewController.currentFrontViewController isKindOfClass:NSClassFromString(@"NIMSessionViewController")]) {
                // 通知不弹出
                if (@available(iOS 14.0, *)) {
                    completionHandler(UNNotificationPresentationOptionBanner);
                } else {
                    completionHandler(UNNotificationPresentationOptionAlert);
                }
            } else {
                completionHandler(UNNotificationPresentationOptionNone);
            }
        } else {
            // 通知弹出，且带有声音、内容
            completionHandler(UNNotificationPresentationOptionSound | UNNotificationPresentationOptionAlert);
        }
    } else {//应用处于前台时的本地推送接受
        if (@available(iOS 14.0, *)) {
            completionHandler(UNNotificationPresentationOptionSound | UNNotificationPresentationOptionAlert |UNNotificationPresentationOptionList|UNNotificationPresentationOptionBanner);
        } else {
            completionHandler(UNNotificationPresentationOptionSound | UNNotificationPresentationOptionAlert);
        }//
    }
}

