@implementation XPLaunchTaskMgr

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

- (instancetype)init {
    if (self = [super init]) {
        _isOnSplashAd = NO;
        _isHomeAppeared = NO;
        _isHomeAppearedDelay = NO;
        _isLaunchHomeReady = NO;
        _isLaunchEventFinished = NO;
        [self startupBBox];
    }
    return self;
}


+ (XPLaunchTaskMgr *)instance {
    static XPLaunchTaskMgr *gXPLaunchTaskMgr = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        gXPLaunchTaskMgr = [[XPLaunchTaskMgr alloc] init];
    });
    return gXPLaunchTaskMgr;
}

