- (void)startupOnInitSecurity:(void(^)(NSError *))complete {
    DLogTagInfo(@"AppLaunch", @"===================== startupOnInitSecurity =====================");
    CFTimeInterval startTime = CACurrentMediaTime();

    // TEE 已生效，直接使用 TEE
    if ([KeyValueStore BOOLForObjectId:XP_TEE_EFFECTIVE_KEY userId:nil]) {
        if (![[XPTeeSecurityManager instance] isIndivSaveSuccess]) {
            [XPToast showLoadingMessage:@"正在初始化应用" showAnimation:NO];
        }
        [self startupOnInitSecurityWithTee:^(NSError *error) {
            [XPToast dismissLoadingMessage];
            if (error == nil
                && XPCoreSessionAppLaunch.sharedInstance.encryptionType != HttpRequestEncryptionTypeTee) {
                [[XPCoreSessionAppLaunch sharedInstance] encryptionReady:HttpRequestEncryptionTypeTee];
            }
            [self reportTaskEvent:__PRETTY_FUNCTION__ startTime:startTime];
            if(complete) complete(error);
        }];
        return;
    }

    [self startupOnInitSecurityWithTee:^(NSError *error) {
        if (error == nil) {
            // 使用 TEE
            [[XPCoreSessionAppLaunch sharedInstance] encryptionReady:HttpRequestEncryptionTypeTee];
            [KeyValueStore saveBOOL:YES withObjectId:XP_TEE_EFFECTIVE_KEY userId:nil];
        }

        [self reportTaskEvent:__PRETTY_FUNCTION__ startTime:startTime];
        if(complete) complete(error);
        return;
    }];
}

- (void)startupOnInitSecurityWithTee:(void(^)(NSError *))complete {

    CFTimeInterval startTime = CACurrentMediaTime();
    [[XPTeeSecurityManager instance] loadIndiv:^(NSError * _Nonnull error, BOOL didInit, CGFloat duration) {

        if (didInit) {//真正有初始化tee
            //埋点-初始化tee的结果
            BOOL isSuccess = (error == nil);

            [Bulk writeWithType:BULK_APM
                          event:@"B047"
                         module:@"P00001"
                           data:@{
                               @"error-code" : @(isSuccess ? 0 : 1),
                               @"error-message" : error == nil ? @"" : error.localizedDescription
                           }];
        }

        [self reportTaskEvent:__PRETTY_FUNCTION__ startTime:startTime];
        complete(error);
    } didInit:^{

        [Bulk writeWithType:BULK_APM event:@"B046" module:@"P00001" data:@{ }];
        [self reportTaskEvent:__PRETTY_FUNCTION__ startTime:startTime];
    }];
}

- (void)startupOnAfterInitSecurity:(void (^)(NSError *))complete {
    DLogTagInfo(@"AppLaunch", @"===================== startupOnAfterInitSecurity =====================");
    CFTimeInterval startTime = CACurrentMediaTime();

    @weakify(self);
    [self startupOnInitRN:^(NSError *error) {
        @strongify(self);
        [self configCameraOperationInfoObserver];
        [self configNetworkObserver];

        [[[NSNotificationCenter defaultCenter] rac_addObserverForName:LogInOutNotification object:nil] subscribeNext:^(NSNotification * _Nullable x) {
            dispatch_async(dispatch_get_main_queue(), ^{
                [XPAPIRequestManager.otaConfigVersionsMap removeAllObjects];
                [SystemConfig updateSystemConfigWithForce:YES];
            });
            //获取推送配置
            [[XPPushManager shareInstance] requestPushSettingData];

            [self vehicleSDKLogin];
            [self.class setupXPLogInfo];
            [XPExtensionHelper setup];
        }];

        dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_HIGH, 0), ^{
            @strongify(self);
            DLogTagInfo(@"AppLaunch", @"startupOnAfterInitSecurity on thread");
            //反作弊SDK，以自动化模式初始化SDK
            [[NTESRiskUniPerception fomentBevelDeadengo] init:NTESRiskPerceptionProductID callback:^(int code, NSString * _Nonnull msg, NSString * _Nonnull content) {
                DLogTagInfo(@"AppLaunch", @"NTESRiskUniPerception，code: %d, msg: %@, content: %@", code, msg, content);
            }];

            [self startupConfigCenter];

            //初始化用户车辆数据，必须等初始化用户数据之后
            [self startupCarControlSDK];

            [XPToDoCenterBridge sharedManager].delegate = [XPToDoCenterManager sharedManager];

            //启动时调一次待办接口
            [[XPToDoCenterManager sharedManager] requestAllToDoList];

            //获取系统配置，因为获取系统配置接口需要在header加上uid参数，所以需要待用户数据初始化后才访问获取系统配置接口
            // 车控业务要求OTA配置尽早获取
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [SystemConfig updateSystemConfigWithForce:YES];
                // 检查版本更新从ota独立出来
                [XPUpgradeAppManager requestUpgradeCheck];
            });
            //设置bugly标签，必须等初始化用户数据之后
            [XPLogFileHandle initCrashReportSDKUserInfo];
            //初始化成功后才能刷新userInfo
            [self refreshUserInfo];

            //请求所有配置
            [[XPConfigsManager sharedManager] requestAllConfigs];

            //尝试上报IDFA
            [XPIDFAManager reportIDFA];

            //初始化主界面
            dispatch_async(dispatch_get_main_queue(), ^{
                [XPKeyboardStatusMgr instance];
                [[XPAccountQuickPassLoginManager shareManager] configureBussinessID:AppNTESLoginID];
                [CTMediator tabBarController];
                [CTMediator preloadCommunity];

                if(complete) complete(nil);
            });

            XPOSSServiceConfig *ossConfig = [XPOSSServiceConfig new];
            ossConfig.getUID = ^long { return CTMediator.uid; };
            ossConfig.getVIN = ^NSString *{ return CTMediator.vin; };
            [XPOssService startupWithConfig:ossConfig];

            [OfflineMessageDispatcher start];

            /// 开启远程提取日志功能
            ///
            /// 因部分调用接口使用到用户 id, 需要在用户模块初始化完成后再启动
            [AutoUploadLogManager startMonitor];

            //开始IM服务
            xp_async_execute_in_main_thread(^{
                [[XPIMKitManager sharedManager] loadBaseData];
            });

            [self reportTaskEvent:__PRETTY_FUNCTION__ startTime:startTime];
        });
    }];
}


