NSString * networkStatusName(AFNetworkReachabilityStatus status)
{
    if (AFNetworkReachabilityStatusNotReachable == status) {
        return @"不可用";
    }
    if (AFNetworkReachabilityStatusReachableViaWWAN == status) {
        return @"手机网络";
    }
    if (AFNetworkReachabilityStatusReachableViaWiFi == status) {
        return @"WIFI";
    }

    return @"未知";
}

- (void)configNetworkObserver {
     [[[[NetworkMonitorManager sharedManager] statusNotReachableSignal] takeUntil:self.rac_willDeallocSignal] subscribeNext:^(id  _Nullable x) {
         DLogTagInfo( kMQTTTag, @"收到网络不可用的消息");
         [XPToast showMessage:BadNetworkTips];
     }];
     [[[[NetworkMonitorManager sharedManager] statusSignal] takeUntil:self.rac_willDeallocSignal] subscribeNext:^(RACTuple * _Nullable value) {
         AFNetworkReachabilityStatus newStatus = ((NSNumber *)value.second).integerValue;
         AFNetworkReachabilityStatus oldStatus = ((NSNumber *)value.first).integerValue;
         DLogTagInfo( kMQTTTag, @"收到网络变化的消息: %@ ==> %@", networkStatusName(oldStatus), networkStatusName(newStatus));
         if (newStatus == AFNetworkReachabilityStatusReachableViaWWAN ||
             newStatus == AFNetworkReachabilityStatusReachableViaWiFi) {
             DLogTagInfo( kMQTTTag, @"收到wan变到wifi的消息，重新再连上");
             // 当前ip地址日志
             [XPFileTransferTools fetchIPAddressWithComplete:nil];
         }
     }];
     [[[[NetworkMonitorManager sharedManager] statusReachableSignal] takeUntil:self.rac_willDeallocSignal] subscribeNext:^(id  _Nullable x) {
         DLogTagInfo( kMQTTTag, @"收到网络可用的消息，重新再连上，5s后获取配置信息，以及如果爱迪徳没有初始化成功，则重新初始化");

         // 当有网时，拉一次配置，防止刚进来时无网，后面有网了
         dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
             [SystemConfig updateSystemConfigWithForce:NO];
             // 二维码需要无网进入，需要白名单判断
             if ([XPQRCodeWhitelistConfig shared].qrcodeWhitelist.count == 0) {
                 [[XPConfigsManager sharedManager] requestAllConfigs];
             }
         });
         //初始化Tee加密
         dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(1.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
             [self startupOnInitSecurity:nil];
         });
         //有网络后查询用户协议是否有更新，防止一进来没有网络
         [CTMediator requestLoginScenePolicyWhenLoginWithAgreeBlock:nil];
     }];
}


#pragma mark -
#pragma mark - background task
- (void)endBackgroundTask {
    DLogTagInfo( kBackgroundTaskTag, @"后台任务时间结束，所有线程即将被挂起");
    [XPCarSDK notifyAppWillSuspend];
    [[XPMatrixHandler shareInstance] notifyAppWillSuspend];
    if ([NSThread isMainThread]) {
        [self.backgroundTaskTimer invalidate];// 停止定时器
        /*  每个对 beginBackgroundTaskWithExpirationHandler:方法的调用,必须要相应的调用 endBackgroundTask:方法。这样，来告诉应用程序你已经执行完成了。
         也就是说,我们向 iOS 要更多时间来完成一个任务,那么我们必须告诉 iOS 你什么时候能完成那个任务。
         标记指定的后台任务完成
         */
        if (self.backgroundTaskIdentifier != UIBackgroundTaskInvalid) {
            [[UIApplication sharedApplication] endBackgroundTask:self.backgroundTaskIdentifier];
            // 销毁后台任务标识符
            self.backgroundTaskIdentifier = UIBackgroundTaskInvalid;
        }

    } else {
        dispatch_sync(dispatch_get_main_queue(), ^(void) {
            [self.backgroundTaskTimer invalidate];// 停止定时器
            /*  每个对 beginBackgroundTaskWithExpirationHandler:方法的调用,必须要相应的调用 endBackgroundTask:方法。这样，来告诉应用程序你已经执行完成了。
             也就是说,我们向 iOS 要更多时间来完成一个任务,那么我们必须告诉 iOS 你什么时候能完成那个任务。
             标记指定的后台任务完成
             */
            if (self.backgroundTaskIdentifier != UIBackgroundTaskInvalid) {
                [[UIApplication sharedApplication] endBackgroundTask:self.backgroundTaskIdentifier];
                // 销毁后台任务标识符
                self.backgroundTaskIdentifier = UIBackgroundTaskInvalid;
            }
        });
    }
}

- (void)endBackgroundTaskIfNeed {
    if(self.backgroundTaskIdentifier != UIBackgroundTaskInvalid) {
        [self.backgroundTaskTimer invalidate];//停止定时器
        [[UIApplication sharedApplication] endBackgroundTask:self.backgroundTaskIdentifier];
        self.backgroundTaskIdentifier = UIBackgroundTaskInvalid;
    }
}

// 模拟的一个 Long-Running Task 方法
- (void)timerMethod:(NSTimer *)paramSender {
    // backgroundTimeRemaining 属性包含了程序留给的我们的时间
    self.backgroundTimeRemaining = [[UIApplication sharedApplication] backgroundTimeRemaining];
    if (self.backgroundTimeRemaining == DBL_MAX) {
        DLogTagInfo( kBackgroundTaskTag, @"Background Time Remaining = Undetermined");
    } else {
        DLogTagInfo( kBackgroundTaskTag, @"Background Time Remaining = %.02f Seconds", self.backgroundTimeRemaining);
    }
}

- (BOOL)appIsBackgroundRunning {
    if([UIApplication sharedApplication].applicationState == UIApplicationStateBackground) {
        if(self.backgroundTimeRemaining < backgroundDisconnectMQTTRemainingTime) {
            DLogTagInfo(kCameraTag, @"后台剩余时间：%f, 小于%d秒，mqtt已断开，app不在后台运行", self.backgroundTimeRemaining, backgroundDisconnectMQTTRemainingTime);
            return NO;
        } else {
            DLogTagInfo(kCameraTag, @"后台剩余时间：%f, 大于%d秒，mqtt未断开，app在后台运行", self.backgroundTimeRemaining, backgroundDisconnectMQTTRemainingTime);
            return YES;
        }
    }

    return NO;
}

