- (void)startupBulk {
    BulkConfig *config = Bulk.config;

    config.logHandler = ^(int level, NSString *module, NSString *file, int line, NSString *func, NSString *message) {
        XLogInternal(level, module.UTF8String, file.UTF8String, line, func.UTF8String, "", @"%@", message);
    };

    config.getUserMyIP = ^NSString * _Nonnull{
        _BulkMyIPInfo *ipinfo = [_BulkMyIPProvider ipinfo];
        return ipinfo.ip;
    };
    config.getExtraData = ^NSDictionary *(BulkExtraDataType type){
        NSDictionary *extras = nil;
        switch (type) {
        case BulkExtraDataTypePackage: {
            extras = @{
                @"position": XPLocationUtils.locationGP,
            };
            break;
        }
        case BulkExtraDataTypeEvent: {
            extras = @{
                @"campaign_id" : @(ReactNativeManager.rvc),
                @"recent_net_cost" : @(XPNetworkTimingCollector.timing),
                @"vin": CTMediator.vin ?: @""
            };
            break;
        }
        case BulkExtraDataTypePara: {
            break;
        }
        default:
            break;
        }
        return extras.copy;
    };

    config.uploadDataHandler = ^(BULK_TYPE type, NSDictionary *data, BulkUploadDataCompletion completion) {
        NSString *domain = nil;
        NSString *path = nil;
        switch (type) {
            case BULK_FULL_POINT:
                domain = @"https://appdata.xiaopeng.com";
                path = APIUrlReportAutodTrackData;
                break;
            case BULK_APM:
                domain = @"https://appdata.xiaopeng.com";
                path = APIUrlReportRealtimeData;
                break;
            default:
                domain = HTTPApiRequestStatisticsDomain;
                path = APIUrlReportStatisticsData;
                break;
        }

        NSError *error = nil;
        NSData *bodyData = [NSJSONSerialization dataWithJSONObject:data options:0 error:&error];
        if (bodyData.length == 0 || error) {
            completion(NO, nil, error);
            return;
        }

        bodyData = [bodyData gzippedData];
        bodyData = [bodyData base64EncodedDataWithOptions:0];
        NSURL *URL = [NSURL URLWithString:[domain stringByAppendingString:path]];
        [BulkNetwork sendData:bodyData URL:URL completion:^(NSData * _Nullable data, NSURLResponse * _Nullable response, NSError * _Nullable error) {
            BOOL isSuccess = NO;
            NSError *err = error;
            if (data.length > 0 && error == nil) {
                NSError *serializeError = nil;
                id obj = [NSJSONSerialization JSONObjectWithData:data options:0 error:&serializeError];
                if (serializeError == nil && [obj isKindOfClass:NSDictionary.class]) {
                    NSDictionary *data = (NSDictionary *)obj;
                    id codeObj = data[@"code"];
                    if ([codeObj isKindOfClass:NSNumber.class]) {
                        NSNumber *code = (NSNumber *)codeObj;
                        if (code.integerValue == 200) {
                            isSuccess = YES;
                        }
                    }
                } else {
                    err = serializeError;
                }
            }
            completion(isSuccess, nil, err);
        }];
    };

    [Bulk startupWithConfig:config];
}

- (void)startupCloudConfig {
    BOOL needForce = XPAPPVersion.initialOperation;
    [CloudConfig setupWithForceUpdate:needForce
                       requestHandler:^(NSString *domain, NSString *path, NSDictionary *payload,
                                        CloudConfigRequestCompletion completion) {
        XPAPI.request.domain(domain)
            .path(path)
            .payload(payload)
            .method(XPAPIRequestMethodPOST)
            .subscribe(^(Response *resp) {
                if (completion == nil) {
                    return;
                }
                completion(resp.originalData, resp.error);
            });
    }];
}

- (void)startupConfigCenter {
    XPConfigCenterConfig *config = [XPConfigCenterConfig new];
    config.getUserTypeBlock = ^NSInteger{
        return [CTMediator currentUserInfo].flag;
    };
    [XPConfigCenter startup:config];
}

- (void)startupCarControlSDK{
    if ([NSThread isMainThread]) {
        [self startupCarControlSDKInner];
    } else {
        dispatch_async(dispatch_get_main_queue(), ^{
            [self startupCarControlSDKInner];
        });
    }
}

- (void)startupCarControlSDKInner{
    [XPVehicleSDK setOTAConfigProxy:[XPOTAConfigBridge shared]];
    [XPVehicleSDK setOCMAppSettingsProxy:[XPAppSettingsBridge shared]];
    [XPVehicleSDK setLogProxy:[XPVehicleLogBridge shared]];
    [XPVehicleSDK setDbProxy:[XPDatabaseBridge shared]];
    [XPVehicleSDK setStatisticsProxy:[XPStatisticsBridge shared]];
    [XPVehicleSDK setKeySettingDataProxy:XPKeySettingDataBridge.shared];
    [XPVehicleSDK setHttpProxy:[XPVehicleHttpBridge shared]];
    [XPVehicleSDK setTextProxy:[XPVehicleTextBridge shared]];
    [XPVehicleSDK setupWithLaunchOptions:self.launchOptions];

    [XPVehicleExt setupWithLaunchOptions:self.launchOptions];
    [XPVehicleExt setupWithDBMessageProxy:[XPDBMessgaeBridge new]];
    [XPPollingSDK setKeySettingDataProxy:[XPKeySettingDataBridge shared]];
    [XPPollingSDK setPollingProxy:[XPPollingProxyBridge shared]];
    [XPPollingSDK setupWithLaunchOptions:self.launchOptions];
    [XPCarSDK startup:self.launchOptions delegate:XPUnityLifeLoopHandler.shareInstance];
    [self vehicleSDKLogin];
}

- (void)vehicleSDKLogin {
    [XPAppSettings enterAccount:CTMediator.uid];
    [XPVehicleSDK.shared.vehicleManager enterAccountWithUid:CTMediator.uid nickname:CTMediator.currentUserInfo.nickName  fetchVehicleList:YES callback:nil];

    if (CTMediator.uid == 0) {
        [XPAppSettings deleteAllSettings];
    }
}


@end

